export interface Station {
  name: string;
  crs: string;
}

export interface LocationDetail {
  realtimeActivated: boolean;
  crs: string;
  description: string;
  gbttBookedArrival?: string;
  gbttBookedDeparture?: string;
  realtimeArrival?: string;
  realtimeDeparture?: string;
  realtimeArrivalActual?: boolean;
  realtimeDepartureActual?: boolean;
  displayAs: string;
}

export interface Service {
  locationDetail: LocationDetail;
  serviceUid: string;
  runDate: string;
  trainIdentity: string;
  runningIdentity: string;
  atocCode: string;
  atocName: string;
  serviceType: string;
  isPassenger: boolean;
  origin: { publicName: string; crs: string }[];
  destination: { publicName: string; crs: string }[];
}

export interface RTTResponse {
  location: {
    name: string;
    crs: string;
  };
  services: Service[] | null;
}

export interface AdjacentStation {
  name: string;
  crs: string;
  direction: 'up' | 'down' | 'next';
}

import { GoogleGenAI, Type } from "@google/genai";
import { AdjacentStation, Station } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function findStationCrs(query: string): Promise<Station[]> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find the 3-letter CRS codes for UK railway stations matching or similar to: "${query}". Return the most likely candidates.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            crs: { type: Type.STRING }
          },
          required: ["name", "crs"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch {
    return [];
  }
}

export async function getAdjacentStations(stationName: string, crs: string): Promise<AdjacentStation[]> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `For the UK railway station "${stationName}" (${crs}), identify the immediate next stations in each major direction (e.g., Up, Down, Northbound, Southbound). Provide the CRS code and name for each adjacent station. Return exactly 2-4 primary adjacent stations.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            crs: { type: Type.STRING },
            direction: { type: Type.STRING, enum: ["up", "down", "next"] }
          },
          required: ["name", "crs", "direction"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch {
    return [];
  }
}

import { RTTResponse } from "../types";

const USERNAME = 'rttapi_bluegruntfuttock@gmail.com';
const PASSWORD = '7c5b8634ff592fe4969a2ae5f4f00303b1c7cc04';

const getAuthHeader = () => {
  return 'Basic ' + btoa(`${USERNAME}:${PASSWORD}`);
};

export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  // Using a CORS proxy if running locally, otherwise standard fetch
  // Note: rttapi usually requires a secure context or server-side calls due to CORS.
  // We will attempt a direct call.
  const url = `https://api.rtt.io/api/v1/json/search/${crs}`;

  try {
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      const errorText = await response.text();
      console.error('RTT API Error:', response.status, errorText);
      throw new Error(`RTT API Error: ${response.status}`);
    }

    const data: RTTResponse = await response.json();
    return data;
  } catch (error) {
    console.error('Fetch Departures Failed:', error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback } from 'react';
import { Station, Service, RTTResponse, AdjacentStation } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getAdjacentStations } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [adjacentStations, setAdjacentStations] = useState<AdjacentStation[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsSearching(true);
    setSearchResults([]);
    try {
      const results = await findStationCrs(searchQuery);
      setSearchResults(results);
    } catch (err) {
      console.error(err);
      setError("Failed to find stations. Please try again.");
    } finally {
      setIsSearching(false);
    }
  };

  const loadStationData = useCallback(async (station: Station) => {
    setLoading(true);
    setError(null);
    setSelectedStation(station);
    setDepartures([]);
    setAdjacentStations([]);

    try {
      // 1. Fetch departures from RTT
      const data = await fetchDepartures(station.crs);
      setDepartures(data.services || []);
      setLastUpdated(new Date());

      // 2. Fetch adjacent stations from Gemini
      const adj = await getAdjacentStations(station.name, station.crs);
      setAdjacentStations(adj);
    } catch (err: any) {
      console.error(err);
      setError(`Unable to load data for ${station.name}. (Check CORS or API credentials)`);
    } finally {
      setLoading(false);
    }
  }, []);

  const calculateStatus = (service: Service) => {
    const planned = service.locationDetail.gbttBookedDeparture;
    const actual = service.locationDetail.realtimeDeparture;

    if (!planned || !actual) return { text: "No Data", color: "text-slate-400" };

    const pMinutes = parseInt(planned.slice(0, 2)) * 60 + parseInt(planned.slice(2));
    const aMinutes = parseInt(actual.slice(0, 2)) * 60 + parseInt(actual.slice(2));

    const diff = aMinutes - pMinutes;

    if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
    if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
    return { text: `${diff} min late`, color: "text-orange-400" };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2)}`;
  };

  return (
    <div className="min-h-screen text-slate-200 p-4 md:p-8 max-w-5xl mx-auto">
      {/* Header */}
      <header className="mb-10 text-center">
        <div className="flex items-center justify-center gap-3 mb-2">
          <div className="p-2 bg-blue-600 rounded-lg text-white">
            <Icons.Train />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-white">UK Rail Live</h1>
        </div>
        <p className="text-slate-400">Real-time departure boards and navigation</p>
      </header>

      {/* Search Section */}
      <section className="bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-2xl p-6 shadow-xl mb-8">
        <form onSubmit={handleSearch} className="flex gap-3">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
              <Icons.Search />
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-3 bg-slate-900 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              placeholder="Search station name (e.g. Waterloo, Reading...)"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
          <button
            type="submit"
            disabled={isSearching}
            className="px-6 py-3 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-semibold rounded-xl transition-colors shadow-lg shadow-blue-900/20"
          >
            {isSearching ? 'Searching...' : 'Search'}
          </button>
        </form>

        {/* Search Results */}
        {searchResults.length > 0 && !selectedStation && (
          <div className="mt-6 grid grid-cols-1 sm:grid-cols-2 gap-2 animate-in fade-in slide-in-from-top-4 duration-300">
            {searchResults.map((s) => (
              <button
                key={s.crs}
                onClick={() => {
                  loadStationData(s);
                  setSearchResults([]);
                }}
                className="flex items-center justify-between p-4 bg-slate-900/50 border border-slate-700 hover:border-blue-500 hover:bg-slate-700/50 rounded-xl group transition-all"
              >
                <div className="text-left">
                  <div className="font-semibold text-white">{s.name}</div>
                  <div className="text-xs text-slate-500 uppercase tracking-widest">{s.crs}</div>
                </div>
                <Icons.ChevronRight />
              </button>
            ))}
          </div>
        )}

        {/* Quick Select */}
        {!selectedStation && searchResults.length === 0 && (
          <div className="mt-8">
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Icons.MapPin /> Major Hubs
            </h3>
            <div className="flex flex-wrap gap-2">
              {MAJOR_STATIONS.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="px-4 py-2 bg-slate-900 border border-slate-700 hover:border-blue-500 hover:bg-slate-700/50 text-slate-300 hover:text-white rounded-full text-sm font-medium transition-all"
                >
                  {s.name}
                </button>
              ))}
            </div>
          </div>
        )}
      </section>

      {/* Main Content */}
      {selectedStation && (
        <main className="space-y-8 animate-in fade-in duration-500">

          {/* Station Context & Navigation */}
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
            <div>
              <div className="text-blue-500 font-bold tracking-widest text-sm mb-1 uppercase">{selectedStation.crs}</div>
              <h2 className="text-4xl font-bold text-white">{selectedStation.name}</h2>
            </div>

            <div className="flex items-center gap-4">
               {lastUpdated && (
                <span className="text-xs text-slate-500 flex items-center gap-1">
                  Updated {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                </span>
               )}
               <button 
                onClick={() => loadStationData(selectedStation)}
                className="p-2 bg-slate-800 border border-slate-700 rounded-lg hover:bg-slate-700 transition-colors text-slate-400 hover:text-white"
                title="Refresh board"
               >
                 <Icons.Refresh />
               </button>
               <button 
                onClick={() => {
                  setSelectedStation(null);
                  setDepartures([]);
                  setAdjacentStations([]);
                }}
                className="text-sm font-medium text-slate-400 hover:text-white underline underline-offset-4"
               >
                 Change Station
               </button>
            </div>
          </div>

          {/* Adjacent Stations Nav */}
          {adjacentStations.length > 0 && (
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
              {adjacentStations.map((adj) => (
                <button
                  key={adj.crs}
                  onClick={() => loadStationData({ name: adj.name, crs: adj.crs })}
                  className="p-3 bg-slate-800/40 border border-slate-700 hover:border-blue-400 rounded-xl text-left transition-all hover:translate-y-[-2px]"
                >
                  <div className="text-[10px] text-slate-500 font-bold uppercase mb-1">{adj.direction} bound</div>
                  <div className="text-sm font-semibold truncate text-slate-200">{adj.name}</div>
                </button>
              ))}
            </div>
          )}

          {/* Departure Board */}
          <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden shadow-2xl">
            {/* Board Header */}
            <div className="grid grid-cols-12 gap-4 px-6 py-4 bg-slate-800/80 border-b border-slate-700 text-xs font-bold uppercase tracking-widest text-slate-400">
              <div className="col-span-2">Time</div>
              <div className="col-span-5">Destination</div>
              <div className="col-span-2 text-center">Status</div>
              <div className="col-span-3 text-right">Carrier</div>
            </div>

            {/* Services */}
            <div className="divide-y divide-slate-800">
              {loading ? (
                <div className="p-12 text-center text-slate-500 italic">
                  Loading the latest departures...
                </div>
              ) : error ? (
                <div className="p-12 text-center space-y-4">
                  <div className="text-rose-400 font-medium">{error}</div>
                  <p className="text-slate-500 text-sm max-w-md mx-auto">
                    This can happen due to CORS restrictions on the browser when calling the RTT API directly, or if the station code is invalid.
                  </p>
                </div>
              ) : departures.length === 0 ? (
                <div className="p-12 text-center text-slate-500">
                  No scheduled departures found for the next 2 hours.
                </div>
              ) : (
                departures.map((service) => {
                  const status = calculateStatus(service);
                  return (
                    <div 
                      key={service.serviceUid + service.runDate}
                      className="grid grid-cols-12 gap-4 px-6 py-5 items-center hover:bg-slate-800/30 transition-colors group cursor-default"
                    >
                      <div className="col-span-2">
                        <div className="text-xl font-bold mono text-white leading-none">
                          {formatTime(service.locationDetail.gbttBookedDeparture)}
                        </div>
                      </div>

                      <div className="col-span-5">
                        <div className="text-lg font-semibold text-slate-100 truncate group-hover:text-blue-400 transition-colors">
                          {service.destination[0]?.publicName || "See Board"}
                        </div>
                        <div className="text-xs text-slate-500 truncate mt-1">
                          via {service.trainIdentity}
                        </div>
                      </div>

                      <div className="col-span-2 text-center">
                        <div className={`text-sm font-bold mono px-2 py-1 rounded-md bg-slate-800/50 ${status.color}`}>
                          {status.text}
                        </div>
                        {status.text !== "On Time" && service.locationDetail.realtimeDeparture && (
                          <div className="text-[10px] text-slate-500 mt-1 uppercase tracking-tighter">
                            Exp {formatTime(service.locationDetail.realtimeDeparture)}
                          </div>
                        )}
                      </div>

                      <div className="col-span-3 text-right">
                        <div className="text-sm font-medium text-slate-300 truncate">
                          {service.atocName}
                        </div>
                        <div className="text-[10px] text-slate-600 font-mono">
                          {service.serviceUid}
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </main>
      )}

      {/* Footer Info */}
      <footer className="mt-20 pt-8 border-t border-slate-800 flex flex-col items-center gap-4 text-slate-500 text-xs text-center">
        <div className="flex items-center gap-6">
          <p>Powered by Realtime Trains API</p>
          <div className="w-1 h-1 bg-slate-700 rounded-full"></div>
          <p>Station Intelligence via Gemini 3</p>
        </div>
        <p>© {new Date().getFullYear()} UK Rail Departures Pro. For demonstration purposes.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, AdjacentStation } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getAdjacentStations } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [adjacentStations, setAdjacentStations] = useState<AdjacentStation[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  // Ref to track the latest query to prevent race conditions in async predictions
  const latestQueryRef = useRef('');

  // Debounced Predictive Search
  useEffect(() => {
    latestQueryRef.current = searchQuery;

    if (searchQuery.trim().length < 2) {
      if (!selectedStation) setSearchResults([]);
      return;
    }

    // Don't predict if we've already selected a station and haven't cleared it
    if (selectedStation && searchQuery === selectedStation.name) return;

    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        // Only update if this is still the current query
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results);
        }
      } catch (err) {
        console.error("Prediction error:", err);
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 400); // 400ms debounce

    return () => clearTimeout(timer);
  }, [searchQuery, selectedStation]);

  const handleSearchSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    // If we already have results from prediction, we don't need to re-fetch unless list is empty
    if (searchResults.length === 0) {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        setSearchResults(results);
      } catch (err) {
        setError("Failed to find stations. Please try again.");
      } finally {
        setIsSearching(false);
      }
    }
  };

  const loadStationData = useCallback(async (station: Station) => {
    setLoading(true);
    setError(null);
    setSelectedStation(station);
    setSearchQuery(station.name); // Set input to the selected name
    setDepartures([]);
    setAdjacentStations([]);
    setSearchResults([]); // Hide results list

    try {
      const data = await fetchDepartures(station.crs);
      setDepartures(data.services || []);
      setLastUpdated(new Date());

      const adj = await getAdjacentStations(station.name, station.crs);
      setAdjacentStations(adj);
    } catch (err: any) {
      console.error(err);
      setError(`Unable to load data for ${station.name}. (Check CORS or API credentials)`);
    } finally {
      setLoading(false);
    }
  }, []);

  const calculateStatus = (service: Service) => {
    const planned = service.locationDetail.gbttBookedDeparture;
    const actual = service.locationDetail.realtimeDeparture;

    if (!planned || !actual) return { text: "No Data", color: "text-slate-400" };

    const pMinutes = parseInt(planned.slice(0, 2)) * 60 + parseInt(planned.slice(2));
    const aMinutes = parseInt(actual.slice(0, 2)) * 60 + parseInt(actual.slice(2));

    const diff = aMinutes - pMinutes;

    if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
    if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
    return { text: `${diff} min late`, color: "text-orange-400" };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2)}`;
  };

  return (
    <div className="min-h-screen text-slate-200 p-4 md:p-8 max-w-5xl mx-auto">
      {/* Header */}
      <header className="mb-10 text-center">
        <div className="flex items-center justify-center gap-3 mb-2">
          <div className="p-2 bg-blue-600 rounded-lg text-white">
            <Icons.Train />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-white">UK Rail Live</h1>
        </div>
        <p className="text-slate-400">Real-time departure boards and navigation</p>
      </header>

      {/* Search Section */}
      <section className="relative z-50 bg-slate-800/50 backdrop-blur-sm border border-slate-700 rounded-2xl p-6 shadow-xl mb-8">
        <form onSubmit={handleSearchSubmit} className="flex gap-3">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
              {isSearching ? (
                <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full ml-1" />
              ) : (
                <Icons.Search />
              )}
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-3 bg-slate-900 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
              placeholder="Start typing station name..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => { if(selectedStation) setSearchQuery('') }}
            />
          </div>
          <button
            type="submit"
            className="hidden sm:block px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-semibold rounded-xl transition-colors shadow-lg shadow-blue-900/20"
          >
            Find
          </button>
        </form>

        {/* Predictions Dropdown */}
        {searchResults.length > 0 && (
          <div className="absolute left-6 right-6 top-full mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2 duration-200">
            <div className="max-h-60 overflow-y-auto divide-y divide-slate-700">
              {searchResults.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
