            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Icons.MapPin /> Major Stations
            </h3>
            <div className="flex flex-wrap gap-2">
              {MAJOR_STATIONS.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="px-4 py-2 bg-slate-900 border border-slate-700 hover:border-blue-500 hover:bg-slate-700 text-slate-300 hover:text-white rounded-full text-xs font-bold transition-all hover:shadow-[0_0_15px_rgba(59,130,246,0.1)]"
                >
                  {s.name}
                </button>
              ))}
            </div>
          </div>
        )}
      </section>

      {/* Main Content */}
      {selectedStation && (
        <main className="space-y-8 animate-in fade-in duration-500">

          {/* Station Context & Actions */}
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-slate-800 pb-8">
            <div className="space-y-1">
              <div className="inline-block px-2 py-0.5 bg-blue-500/10 border border-blue-500/20 rounded text-blue-500 font-bold tracking-[0.3em] text-[10px] uppercase mb-1">
                {selectedStation.crs}
              </div>
              <h2 className="text-4xl font-extrabold text-white tracking-tight">{selectedStation.name}</h2>
              {lastUpdated && (
                <div className="text-xs text-slate-500 font-medium">
                  Last updated {lastUpdated.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                </div>
