          </div>

          {/* Adjacent Stations */}
          {adjacentStations.length > 0 && (
            <div className="space-y-4">
               <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Next Stop Navigation</h3>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {adjacentStations.map((adj) => (
                  <button
