/**
 * Fetches departures from Realtime Trains API.
 * Uses a CORS proxy to bypass browser restrictions.
 */
export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  const targetUrl = `https://api.rtt.io/api/v1/json/search/${crs}`;
  // Using corsproxy.io as it handles Basic Auth well
  const proxiedUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl)}`;

  try {
    const response = await fetch(proxiedUrl, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      if (response.status === 401 || response.status === 403) {
        throw new Error("API Authentication failed. Please verify credentials.");
      }
      throw new Error(`Station lookup failed (Status: ${response.status})`);
    }

    const data: RTTResponse = await response.json();

    if (data.error) {
      throw new Error(`RTT API: ${data.error}`);
    }

    // Defensive sorting: Ensure services is an actual array
    if (data.services && Array.isArray(data.services)) {
      data.services.sort((a, b) => {
        const timeA = a.locationDetail?.gbttBookedDeparture || "0000";
        const timeB = b.locationDetail?.gbttBookedDeparture || "0000";
        return timeA.localeCompare(timeB);
      });
    } else if (data.services !== null && typeof data.services !== 'undefined') {
       // If it exists but isn't an array, normalize it
       data.services = [];
    }

    return data;
  } catch (error: any) {
    console.error('RTT Fetch Error:', error);

    if (error.message.includes('Failed to fetch')) {
      throw new Error("Network error: The CORS proxy is unavailable or blocked.");
    }

    throw error;
  }
}

