  locationDetail: LocationDetail;
  serviceUid: string;
  runDate: string;
  trainIdentity: string;
  runningIdentity?: string;
  atocCode?: string;
  atocName?: string;
  serviceType?: string;
  isPassenger?: boolean;
  // Some versions of RTT API use different keys for the station name
  origin?: Array<{ 
    description?: string; 
    locationName?: string; 
    publicName?: string; 
    workingTime?: string; 
    publicTime?: string 
  }>;
  destination?: Array<{ 
    description?: string; 
    locationName?: string; 
    publicName?: string; 
    workingTime?: string; 
    publicTime?: string 
  }>;
}

export interface RTTResponse {
  location?: {
    name: string;
    crs: string;
  };
  services?: Service[] | null;
