};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, AdjacentStation } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getAdjacentStations, getRouteCallingPoints } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [adjacentStations, setAdjacentStations] = useState<AdjacentStation[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setSearchResults([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      return;
    }
    if (selectedStation && searchQuery.toLowerCase() === selectedStation.name.toLowerCase()) {
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
        }
      } catch (err) {
        console.error("Prediction error:", err);
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery, selectedStation]);

  // Robust station name extraction
  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station) => {
    if (!station || !station.crs) return;

    setLoading(true);
    setError(null);
    setSelectedStation(station);
    setSearchQuery(station.name);
    setDepartures([]);
    setAdjacentStations([]);
    setSearchResults([]); 

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      // Initial set with basic data
      setDepartures(services);
      setLastUpdated(new Date());

      // Fetch adjacent stations
      getAdjacentStations(station.name, station.crs)
        .then(adj => {
          if (Array.isArray(adj)) setAdjacentStations(adj);
        })
        .catch(e => console.warn("Could not load adjacent stations:", e));

      // Enrichment logic for calling points
      if (services.length > 0) {
        // Collect unique route combinations
        const uniqueRoutes = services.slice(0, 15).map(s => {
          const origin = getStationName(s.origin) || "Unknown";
          const dest = getFullDestinationName(s);
          return { origin, destination: dest };
        }).filter((v, i, a) => a.findIndex(t => (t.origin === v.origin && t.destination === v.destination)) === i);

        getRouteCallingPoints(uniqueRoutes.map(r => ({ ...r, via: station.name }))).then(enrichedMap => {
          setDepartures(prev => prev.map(s => {
            const origin = getStationName(s.origin) || "Unknown";
            const dest = getFullDestinationName(s);
            const key = `${origin} - ${dest}`;

            // Try exact key or partial match
            const points = enrichedMap[key] || enrichedMap[dest] || [];

            return { ...s, callingPoints: points.length > 0 ? points : undefined };
          }));
        });
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchResults.length > 0) {
      loadStationData(searchResults[0]);
    }
  };

  const calculateStatus = (service: Service) => {
    if (!service || !service.locationDetail) return { text: "No Data", color: "text-slate-500" };

    const planned = service.locationDetail.gbttBookedDeparture || service.locationDetail.gbttBookedArrival;
    const actual = service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);

      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
      return { text: `${diff} min late`, color: "text-orange-400" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  return (
    <div className="min-h-screen text-slate-200 p-4 md:p-8 max-w-5xl mx-auto pb-24">
      <header className="mb-10 text-center">
        <div className="flex items-center justify-center gap-3 mb-2">
          <div className="p-2 bg-blue-600 rounded-lg text-white shadow-lg shadow-blue-500/20">
            <Icons.Train />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-white">UK Rail Live</h1>
        </div>
        <p className="text-slate-400 text-sm font-medium">Precision Departure Board & Route Finder</p>
      </header>

      <section className="relative z-50 bg-slate-800/40 backdrop-blur-md border border-slate-700/50 rounded-2xl p-6 shadow-2xl mb-8">
        <form onSubmit={handleSearchSubmit} className="flex gap-3">
          <div className="relative flex-1">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-500">
              {isSearching ? (
                <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full ml-1" />
              ) : (
                <Icons.Search />
              )}
            </div>
            <input
              type="text"
              className="block w-full pl-10 pr-3 py-3 bg-slate-900 border border-slate-700 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
              placeholder="Enter station name..."
              value={searchQuery}
              autoComplete="off"
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => { if(selectedStation) setSearchQuery('') }}
            />
          </div>
          <button
            type="submit"
            className="hidden sm:block px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-semibold rounded-xl transition-all shadow-lg shadow-blue-900/40 active:scale-95"
          >
            Search
          </button>
        </form>

        {searchResults.length > 0 && (
          <div ref={dropdownRef} className="absolute left-6 right-6 top-full mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden z-50">
            <div className="max-h-60 overflow-y-auto divide-y divide-slate-700/50">
              {searchResults.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="w-full flex items-center justify-between p-4 hover:bg-slate-700/80 text-left transition-colors group"
                >
                  <div>
                    <div className="font-semibold text-white group-hover:text-blue-400 transition-colors">{s.name}</div>
                    <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mt-0.5">{s.crs}</div>
                  </div>
                  <div className="text-slate-600 group-hover:text-blue-500 group-hover:translate-x-1 transition-all">
                    <Icons.ChevronRight />
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {!selectedStation && searchResults.length === 0 && !searchQuery && (
          <div className="mt-8">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Icons.MapPin /> Major Hubs
            </h3>
            <div className="flex flex-wrap gap-2">
              {MAJOR_STATIONS.map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="px-4 py-2 bg-slate-900 border border-slate-700 hover:border-blue-500 hover:bg-slate-700 text-slate-300 hover:text-white rounded-full text-xs font-bold transition-all"
                >
                  {s.name}
                </button>
              ))}
            </div>
          </div>
        )}
      </section>

      {selectedStation && (
        <main className="space-y-8 animate-in fade-in duration-500">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 border-b border-slate-800 pb-8">
            <div className="space-y-1">
              <div className="inline-block px-2 py-0.5 bg-blue-500/10 border border-blue-500/20 rounded text-blue-500 font-bold tracking-[0.3em] text-[10px] uppercase mb-1">
                {selectedStation.crs}
              </div>
              <h2 className="text-4xl font-extrabold text-white tracking-tight leading-tight">{selectedStation.name}</h2>
              {lastUpdated && (
                <div className="text-xs text-slate-500 font-medium">
                  Last updated {lastUpdated.toLocaleTimeString()}
                </div>
              )}
            </div>

            <div className="flex items-center gap-3">
               <button 
                onClick={() => loadStationData(selectedStation)}
                disabled={loading}
                className="flex items-center gap-2 px-4 py-2 bg-slate-800 border border-slate-700 rounded-xl hover:bg-slate-700 transition-all text-slate-300 hover:text-white disabled:opacity-50"
               >
                 <div className={loading ? "animate-spin" : ""}>
                    <Icons.Refresh />
                 </div>
                 <span className="text-sm font-bold">Refresh</span>
               </button>
               <button 
                onClick={() => {
                  setSelectedStation(null);
                  setSearchQuery('');
                  setDepartures([]);
                  setAdjacentStations([]);
                }}
                className="px-4 py-2 text-sm font-bold text-slate-400 hover:text-white transition-colors"
               >
                 Reset
               </button>
            </div>
          </div>

          {adjacentStations.length > 0 && (
            <div className="space-y-4">
               <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.2em]">Next Stations</h3>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {adjacentStations.map((adj, i) => (
                  <button
                    key={`${adj.crs}-${adj.direction}-${i}`}
                    onClick={() => loadStationData({ name: adj.name, crs: adj.crs })}
                    className="p-4 bg-slate-800/20 border border-slate-700/50 hover:border-blue-500/50 hover:bg-slate-800/50 rounded-2xl text-left transition-all group relative"
                  >
                    <div className="text-[9px] text-blue-500/70 font-black uppercase mb-1">{adj.direction} bound</div>
                    <div className="text-sm font-bold truncate text-slate-200 group-hover:text-white">{adj.name || adj.crs}</div>
                    <div className="absolute right-2 bottom-2 text-slate-700 group-hover:text-blue-500/10 transition-colors">
                        <Icons.Train />
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl ring-1 ring-white/5">
            <div className="hidden md:grid grid-cols-12 gap-4 px-8 py-5 bg-slate-800/40 border-b border-slate-800 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">
              <div className="col-span-2">Scheduled</div>
              <div className="col-span-7">Destination & Route</div>
              <div className="col-span-3 text-right">Status</div>
            </div>

            <div className="divide-y divide-slate-800/50">
              {loading ? (
                <div className="p-20 text-center flex flex-col items-center gap-6">
                  <div className="h-12 w-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin" />
                  <div className="text-slate-400 font-bold text-sm tracking-widest uppercase">Fetching Board...</div>
                </div>
              ) : error ? (
                <div className="p-16 text-center space-y-6">
                  <div className="inline-flex p-4 bg-rose-500/10 rounded-full text-rose-500">
                    <Icons.Refresh />
                  </div>
                  <div className="space-y-2">
                    <h3 className="text-white font-bold text-lg">Unable to load services</h3>
                    <p className="text-slate-500 text-sm max-w-sm mx-auto leading-relaxed">{error}</p>
                  </div>
                  <button 
                    onClick={() => loadStationData(selectedStation)}
                    className="px-6 py-2 bg-slate-800 border border-slate-700 rounded-xl text-white text-sm font-bold hover:bg-slate-700 transition-all"
                  >
                    Try Again
                  </button>
                </div>
              ) : departures.length === 0 ? (
                <div className="p-20 text-center space-y-2">
                  <div className="text-slate-400 font-bold text-lg">No services scheduled</div>
                  <div className="text-slate-600 text-sm">There are no departures in the current window.</div>
                </div>
              ) : (
                departures.map((service, idx) => {
                  const status = calculateStatus(service);
                  const destinationName = getFullDestinationName(service);
                  const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;

                  return (
                    <div 
                      key={`${service.serviceUid}-${idx}`}
                      className="grid grid-cols-12 gap-4 px-6 md:px-8 py-6 items-center hover:bg-white/[0.02] transition-colors group"
                    >
                      <div className="col-span-3 md:col-span-2">
                        <div className="text-2xl font-black mono text-white leading-none">
                          {formatTime(scheduledTime)}
                        </div>
                      </div>

                      <div className="col-span-6 md:col-span-7 overflow-hidden">
                        <div className="text-lg font-bold text-slate-100 truncate group-hover:text-blue-400 transition-colors tracking-tight">
                          {destinationName}
                        </div>

                        {/* Calling Points / Intermediate Stations */}
                        <div className="mt-2 flex items-center gap-2 overflow-x-auto no-scrollbar scroll-smooth">
                           <span className="text-[9px] font-black text-slate-600 uppercase whitespace-nowrap">Calling At:</span>
