  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse } from './types';
import { fetchDepartures } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const latestQueryRef = useRef('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Search logic
  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
        }
      } catch (err) {
        console.error("Prediction error:", err);
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) {
      if (obj.length === 0) return "";
      return getStationName(obj[obj.length - 1]);
    }
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) {
      name = getStationName(service.locationDetail.destination);
    }
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station) => {
    if (!station || !station.crs) return;

    setLoading(true);
    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setDepartures([]);
    setSearchResults([]); 
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults || enrichedResults.length === 0) return;

          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );

            if (match && match.stops.length > 0) {
              return { ...s, callingPoints: match.stops };
            }
            return s;
          }));
        }).catch(err => {
          console.warn("Failed to fetch calling points:", err);
        }).finally(() => {
          setEnriching(false);
        });
      }

    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  }, []);

  const calculateStatus = (service: Service) => {
    if (!service || !service.locationDetail) return { text: "No Data", color: "text-slate-500" };
    const planned = service.locationDetail.gbttBookedDeparture || service.locationDetail.gbttBookedArrival;
    const actual = service.locationDetail.realtimeDeparture || service.locationDetail.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400" }; 

    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff <= 0) return { text: "On Time", color: "text-emerald-400" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400" };
      return { text: `${diff} min late`, color: "text-orange-400" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
  };

  // 1. SEARCH VIEW
  if (!selectedStation) {
    return (
      <div className="min-h-screen text-slate-200 flex flex-col items-center justify-center p-6 sm:p-10 transition-all bg-[#0b1120]">
        <div className="w-full max-w-2xl animate-in fade-in slide-in-from-bottom-10 duration-700">
          <header className="mb-12 text-center">
            <div className="inline-block p-4 bg-blue-600 rounded-3xl text-white shadow-2xl shadow-blue-500/20 mb-6">
              <Icons.Train />
            </div>
            <h1 className="text-4xl md:text-5xl font-black tracking-tighter text-white mb-2 italic">UK RAIL LIVE</h1>
            <p className="text-slate-500 text-sm font-black uppercase tracking-[0.3em]">Smart Departure Intelligence</p>
          </header>

          <div className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-3xl blur opacity-20 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
            <div className="relative bg-slate-900 border border-slate-700 rounded-3xl p-2 shadow-2xl">
              <div className="relative flex items-center">
                <div className="absolute left-5 text-slate-500">
                  {isSearching ? <div className="animate-spin h-5 w-5 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-14 pr-6 py-6 bg-transparent text-white placeholder-slate-500 focus:outline-none text-xl md:text-2xl font-bold"
                  placeholder="Where are you starting?"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>

              {searchResults.length > 0 && (
                <div className="mt-2 border-t border-slate-800 max-h-80 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button
                      key={s.crs}
                      onClick={() => loadStationData(s)}
                      className="w-full flex items-center justify-between p-5 hover:bg-white/5 text-left transition-colors group"
                    >
                      <div>
                        <div className="font-bold text-white group-hover:text-blue-400 text-xl">{s.name}</div>
                        <div className="text-[10px] text-slate-600 uppercase font-black tracking-widest mt-1">{s.crs}</div>
                      </div>
                      <Icons.ChevronRight />
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="mt-12">
            <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.4em] mb-6 text-center">Popular Hubs</h3>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              {MAJOR_STATIONS.slice(0, 9).map((s) => (
                <button
                  key={s.crs}
                  onClick={() => loadStationData(s)}
                  className="px-4 py-4 bg-slate-900/50 border border-slate-800 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-2xl text-xs font-bold transition-all truncate"
                >
                  {s.name}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // 2. DEPARTURES VIEW
  return (
    <div className="min-h-screen bg-black text-slate-100 selection:bg-blue-500/30">
      {/* Top Navigation Bar */}
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/80 backdrop-blur-xl border-b border-white/10 px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="flex flex-col">
             <div className="flex items-center gap-2">
                <span className="text-blue-500 font-black tracking-widest text-[10px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
             </div>
             <h1 className="text-xl md:text-3xl font-black tracking-tighter uppercase italic">{selectedStation.name}</h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
           <button 
             onClick={() => loadStationData(selectedStation)}
             className="p-3 text-slate-400 hover:text-white transition-colors"
             title="Refresh"
           >
             <div className={loading ? "animate-spin" : ""}>
                <Icons.Refresh />
             </div>
           </button>
           <button 
             onClick={resetToSearch}
             className="flex items-center gap-2 px-4 py-2 md:px-6 md:py-3 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[10px] md:text-xs uppercase tracking-widest transition-all shadow-lg active:scale-95"
           >
             <Icons.Search />
             <span className="hidden sm:inline">New Search</span>
           </button>
        </div>
      </nav>

      {/* Main Board Content */}
      <main className="pt-24 pb-12 px-2 sm:px-4 md:px-8 max-w-[1400px] mx-auto animate-in fade-in zoom-in-95 duration-500">
        <div className="rounded-[2.5rem] bg-[#0c0c0c] border border-white/5 shadow-[0_0_100px_-20px_rgba(0,0,0,1)] overflow-hidden">
          {/* Board Headers - Landscape Only */}
          <div className="hidden md:grid grid-cols-12 gap-4 px-10 py-6 bg-zinc-900/30 border-b border-white/5 text-[9px] font-black uppercase tracking-[0.5em] text-zinc-500">
            <div className="col-span-2">Scheduled</div>
            <div className="col-span-7">Destination / Calling Points</div>
            <div className="col-span-3 text-right">Service Status</div>
          </div>

          <div className="divide-y divide-white/5">
            {loading ? (
              <div className="p-40 text-center flex flex-col items-center gap-8">
                <div className="relative">
                  <div className="h-20 w-20 border-[6px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                  <div className="absolute inset-0 flex items-center justify-center text-blue-500">
                    <Icons.Train />
                  </div>
                </div>
                <div className="text-slate-500 font-black text-[10px] tracking-[0.5em] uppercase animate-pulse">Scanning Platform...</div>
              </div>
            ) : error ? (
              <div className="p-24 text-center space-y-8">
                <div className="text-rose-500 text-6xl">⚠️</div>
                <div className="space-y-3">
                  <h3 className="text-white font-black text-3xl italic">CONNECTION ERROR</h3>
                  <p className="text-slate-500 text-sm max-w-sm mx-auto font-bold uppercase tracking-widest">{error}</p>
                </div>
                <button 
                  onClick={() => loadStationData(selectedStation)}
                  className="px-12 py-5 bg-white text-black rounded-2xl font-black uppercase tracking-[0.2em] transition-all hover:scale-105"
                >
                  Retry Link
                </button>
              </div>
            ) : departures.length === 0 ? (
              <div className="p-40 text-center">
                <div className="text-slate-700 font-black text-4xl uppercase italic opacity-20 tracking-tighter mb-4">BOARD CLEAR</div>
                <div className="text-slate-600 text-[10px] font-black uppercase tracking-[0.3em]">No services found in this time window.</div>
              </div>
            ) : (
              departures.map((service, idx) => {
                const status = calculateStatus(service);
                const destinationName = getFullDestinationName(service);
                const scheduledTime = service.locationDetail?.gbttBookedDeparture || service.locationDetail?.gbttBookedArrival;

                return (
                  <div 
                    key={`${service.serviceUid}-${idx}`}
                    className="grid grid-cols-12 gap-4 px-6 md:px-10 py-8 items-start md:items-center hover:bg-white/[0.02] transition-colors group relative"
                  >
                    {/* Time Column */}
                    <div className="col-span-3 md:col-span-2">
                      <div className="text-3xl md:text-5xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                        {formatTime(scheduledTime)}
                      </div>
                    </div>

                    {/* Destination & Route */}
                    <div className="col-span-9 md:col-span-7">
                      <div className="text-xl md:text-4xl font-black text-slate-100 uppercase tracking-tight group-hover:translate-x-1 transition-transform leading-none mb-3">
                        {destinationName}
                      </div>

                      <div className="flex flex-wrap items-center gap-x-3 gap-y-2">
                         {service.callingPoints ? (
                           <>
