            <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.4em]">Real-time Departure Intelligence</p>
          </header>

          <div className="relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl blur opacity-10 group-hover:opacity-25 transition duration-500"></div>
