              <div className="relative flex items-center">
                <div className="absolute left-4 text-slate-500">
                  {isSearching ? <div className="animate-spin h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-12 pr-5 py-4 bg-transparent text-white placeholder-slate-500 focus:outline-none text-lg md:text-xl font-bold"
                  placeholder="Starting station..."
                  value={searchQuery}
