import { GoogleGenAI, Type } from "@google/genai";
import { Station } from "../types";

export async function findStationCrs(query: string): Promise<Station[]> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find official UK National Rail stations for: "${query}". 
      Return the 3-letter CRS codes and names. 

      RULES:
      1. ONLY return National Rail stations (no London Underground-only stations unless they share with NR).
      2. For duplicate names (e.g., Richmond, Ash, Gillingham), you MUST include the county/city in brackets. Examples: "Richmond (London)", "Richmond (Yorks)".
      3. For "West Ham", the name is "West Ham" and the CRS is "WEH". Do not return "WHM".
      4. Ensure names are formatted for a professional departure board.
      5. Limit to the 5 most relevant results.`,
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              crs: { type: Type.STRING }
            },
            required: ["name", "crs"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    try {
      const results = JSON.parse(text);
      // Clean up common mis-identifications
      return results.map((r: any) => ({
        ...r,
        crs: r.crs.toUpperCase().trim()
      }));
    } catch (e) {
      console.error("JSON parse error in station search:", text);
      return [];
    }
  } catch (err) {
    console.error("Station search error:", err);
    throw new Error("Lookup service unavailable. Please try again.");
  }
}

export interface RouteStops {
  destination: string;
  stops: string[];
}

export async function getRouteCallingPoints(routes: {origin: string, via: string, destination: string}[]): Promise<RouteStops[]> {
  if (routes.length === 0) return [];

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const viaStation = routes[0].via;
  const routeList = routes.map(r => `- To ${r.destination}`).join('\n');

  const prompt = `For a train at "${viaStation}", list 3-5 major intermediate calling points it will stop at BEFORE reaching the following destinations.
Destinations:
${routeList}

Instructions:
1. ONLY include stops between "${viaStation}" and the final Destination.
2. Return a list of objects containing the "destination" and the array of "stops".`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              destination: { type: Type.STRING },
              stops: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["destination", "stops"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];
    try {
      return JSON.parse(text);
    } catch (e) {
      return [];
    }
  } catch (err) {
    console.error("Calling points enrichment error:", err);
    return [];
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
