const RECENT_STATIONS_KEY = 'uk_rail_recent_stations';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    const saved = localStorage.getItem(RECENT_STATIONS_KEY);
    if (saved) {
      try {
        setRecentStations(JSON.parse(saved));
      } catch (e) {
        setRecentStations([]);
      }
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError(err.message || "Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) return obj.length > 0 ? getStationName(obj[obj.length - 1]) : "";
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) name = getStationName(service.locationDetail.destination);
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    setRecentStations(prev => {
      const filtered = prev.filter(s => s.crs !== station.crs);
      const updated = [station, ...filtered].slice(0, 12);
      localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated));
      return updated;
    });

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];
      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      if (!silent) setError(err.message || "Connection error occurred.");
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
    } catch (err: any) {
      alert("Error: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Departure Board Refresh
  useEffect(() => {
    if (!selectedStation || selectedService) return;
    const interval = setInterval(() => loadStationData(selectedStation, true), 30000);
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, loadStationData]);

  // Journey Timeline Refresh
  useEffect(() => {
    if (!selectedService) return;
    const interval = setInterval(async () => {
      try {
        const details = await fetchServiceDetails(selectedService.serviceUid, selectedService.runDate);
        setSelectedService(details);
        setLastUpdated(new Date());
      } catch (err) {
        console.error("Refresh failed", err);
      }
    }, 30000);
    return () => clearInterval(interval);
  }, [selectedService?.serviceUid, selectedService?.runDate]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };
    if (!actual || actual === planned) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" }; 
    try {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;
      if (diff <= 0) return { text: "On Time", color: "text-emerald-400", bg: "bg-emerald-400/10" };
      if (diff > 59) return { text: "Delayed", color: "text-rose-400", bg: "bg-rose-400/10" };
      return { text: `${diff}m Late`, color: "text-orange-400", bg: "bg-orange-400/10" };
    } catch (e) {
      return { text: "Live", color: "text-blue-400", bg: "bg-blue-400/10" };
    }
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    const parts = dateStr.split(/[-/]/);
    return parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : dateStr;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
  };

  const closeServiceDetail = () => setSelectedService(null);

  if (!selectedStation) {
    const stationsToDisplay = recentStations.length > 0 ? recentStations : MAJOR_STATIONS.slice(0, 12);
    const stationsHeading = recentStations.length > 0 ? "Recent Terminals" : "Major Hubs";

    return (
      <div className="h-screen w-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-24 p-4 sm:p-6 bg-[#0b1120] overflow-hidden">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-8 flex items-center justify-center gap-4">
            <div className="p-2.5 bg-blue-600 rounded-2xl text-white shadow-2xl shadow-blue-500/20"><Icons.Train /></div>
            <div className="text-left">
              <h1 className="text-2xl md:text-4xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] mt-1">Real-time Terminal</p>
            </div>
          </header>

          <div className="relative group mb-8">
            <div className="relative bg-slate-900 border border-slate-700/50 rounded-2xl p-1 shadow-2xl">
              <div className="relative flex items-center">
                <div className="absolute left-5 text-slate-500">
                  {isSearching ? <div className="animate-spin h-5 w-5 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-14 pr-6 py-4 bg-transparent text-white placeholder-slate-600 focus:outline-none text-lg md:text-xl font-bold"
                  placeholder="Find a station..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>
              {searchError && <div className="px-5 py-3 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">{searchError}</div>}
              {searchResults.length > 0 && (
                <div className="mt-1 border-t border-slate-800 max-h-64 overflow-y-auto no-scrollbar">
                  {searchResults.map((s) => (
                    <button key={s.crs} onClick={() => loadStationData(s)} className="w-full flex items-center justify-between p-4 hover:bg-white/5 text-left transition-all group">
                      <div className="flex items-baseline gap-3">
                        <div className="font-bold text-white group-hover:text-blue-400 text-base md:text-lg">{s.name}</div>
                        <div className="text-[10px] text-slate-600 uppercase font-black tracking-widest bg-slate-800/50 px-1.5 py-0.5 rounded">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 transition-transform group-hover:translate-x-1"><Icons.ChevronRight /></div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-8">
              <div className="flex items-center gap-4 mb-5">
                <div className="h-px bg-slate-800/50 flex-1"></div>
                <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.5em]">{stationsHeading}</h3>
                <div className="h-px bg-slate-800/50 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                {stationsToDisplay.map((s) => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="px-3 py-2.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-xl text-[10px] font-bold transition-all truncate text-center">
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="z-50 bg-black/95 backdrop-blur-2xl border-b border-white/5 px-4 md:px-10 py-3 md:py-5 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-5">
          {selectedService && (
             <button onClick={closeServiceDetail} className="p-2.5 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-all active:scale-90">
                <div className="rotate-180 scale-150"><Icons.ChevronRight /></div>
             </button>
          )}
          <div className="flex flex-col">
             <div className="flex items-center gap-2 mb-0.5">
                <span className="text-blue-500 font-black tracking-widest text-[10px] uppercase">{selectedStation.crs}</span>
                <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
             </div>
             <h1 className="text-lg md:text-3xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[200px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-4 md:gap-12">
           <div className="flex flex-col items-end opacity-90 hidden sm:flex">
             <span className="text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-1">Live Update</span>
             <div className="mono text-emerald-400 text-sm md:text-2xl font-bold tracking-[0.2em] drop-shadow-[0_0_12px_rgba(52,211,153,0.4)] bg-emerald-500/5 px-3 py-1 rounded-lg border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>
           <div className="flex items-center gap-2 md:gap-3">
             <button onClick={toggleFullscreen} className="p-2 md:p-3 text-slate-500 hover:text-white bg-white/5 hover:bg-white/10 rounded-xl transition-all active:scale-90">
               {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
             </button>
             <button onClick={resetToSearch} className="flex items-center gap-2 px-4 py-2 md:px-7 md:py-3 bg-white text-black hover:bg-slate-200 rounded-full font-black text-[10px] md:text-sm uppercase tracking-widest transition-all shadow-xl active:scale-95">
               <Icons.Search /> <span className="hidden md:inline">Station Search</span>
             </button>
           </div>
        </div>
      </nav>

      <main className="flex-1 overflow-hidden p-2 md:p-6 lg:p-10 max-w-[1800px] mx-auto w-full animate-in">
        <div className="h-full rounded-2xl md:rounded-3xl bg-[#0c0c0c] border border-white/5 shadow-2xl flex flex-col overflow-hidden relative">

          {!selectedService && (
            <>
              <div className="grid grid-cols-12 gap-4 px-6 md:px-10 py-3 bg-zinc-900/30 border-b border-white/5 text-[10px] font-black uppercase tracking-[0.5em] text-zinc-500 shrink-0">
                <div className="col-span-3 md:col-span-2">Time</div>
                <div className="col-span-9 md:col-span-10">Destination & Intermediate Stops</div>
              </div>
              <div className="flex-1 overflow-y-auto no-scrollbar divide-y divide-white/5">
                {loading || isServiceLoading ? (
                  <div className="h-full w-full flex flex-col items-center justify-center gap-6">
                    <div className="h-16 w-16 border-[4px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    <div className="text-slate-500 font-black text-[10px] tracking-[0.4em] uppercase">Updating Terminal...</div>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full w-full flex flex-col items-center justify-center p-20 opacity-20">
                    <div className="text-slate-400 font-black text-6xl uppercase italic tracking-tighter">No Departures</div>
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destination = getFullDestinationName(service);
                    return (
                      <button key={`${service.serviceUid}-${idx}`} onClick={() => handleServiceClick(service)} className="w-full text-left grid grid-cols-12 gap-3 md:gap-6 px-6 md:px-10 py-6 items-start hover:bg-white/[0.02] transition-all group border-none">
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className="text-3xl md:text-6xl font-black mono text-white leading-none tracking-tighter group-hover:text-blue-500 transition-colors">
                            {formatTime(service.locationDetail.gbttBookedDeparture || service.locationDetail.realtimeDeparture)}
                          </div>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-3 mb-2">
                            <div className="text-xl md:text-5xl font-black text-slate-100 uppercase tracking-tighter leading-none">{destination}</div>
                            <div className={`text-[10px] font-black uppercase tracking-[0.2em] px-2 py-1 rounded-lg ${status.bg} ${status.color}`}>{status.text}</div>
                          </div>
                          <div className="flex flex-wrap items-center gap-x-4 gap-y-1">
                             {service.callingPoints ? (
                               <div className="flex items-center gap-2 overflow-hidden">
                                 <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-2 py-0.5 rounded">Via:</span>
                                 {service.callingPoints.map((stop, sIdx) => (
                                   <React.Fragment key={sIdx}>
                                     <span className="text-[10px] md:text-[14px] font-medium text-slate-500 group-hover:text-slate-300 transition-colors whitespace-nowrap">{stop}</span>
                                     {sIdx < service.callingPoints!.length - 1 && <div className="w-1 h-1 bg-slate-800 rounded-full" />}
                                   </React.Fragment>
                                 ))}
                               </div>
                             ) : <span className="text-[10px] text-zinc-800 font-black uppercase tracking-[0.4em]">Direct Express Service</span>}
                             <div className="ml-auto flex items-center gap-4 hidden md:flex">
                               {service.locationDetail.platform && (
                                 <div className="flex flex-col items-end">
                                    <span className="text-[7px] font-black text-zinc-700 uppercase tracking-widest">Platform</span>
                                    <span className="text-xl font-black text-white">{service.locationDetail.platform}</span>
                                 </div>
                               )}
                             </div>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {selectedService && (
            <div className="flex-1 flex flex-col overflow-hidden animate-in">
              <header className="px-6 md:px-12 py-6 md:py-10 flex flex-row items-center justify-between gap-6 border-b border-white/5 bg-zinc-900/10">
                <div>
                  <div className="flex items-center gap-3 mb-2">
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-[0.5em]">{selectedService.trainIdentity}</span>
                    <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
                    <span className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest border border-white/5 px-2 py-0.5 rounded">Auto-Refreshing (30s)</span>
                  </div>
                  <h2 className="text-2xl md:text-6xl font-black italic uppercase tracking-tighter text-white leading-none">Journey Timeline</h2>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[8px] font-black text-slate-600 uppercase tracking-[0.5em] mb-1">Updated at {lastUpdated?.toLocaleTimeString('en-GB', { hour12: false })}</span>
                  <div className="text-lg md:text-2xl font-bold text-slate-300 uppercase leading-none tracking-widest">{formatDate(selectedService.runDate)}</div>
                </div>
              </header>

              <div className="flex-1 overflow-y-auto no-scrollbar p-6 md:p-12 relative">
                <div className="max-w-4xl mx-auto space-y-2 relative">
                  <div className="absolute left-[2.4rem] md:left-[3.9rem] top-10 bottom-10 w-1 bg-zinc-900" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isCurrent = loc.crs === selectedStation?.crs;
                    const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                    const actual = loc.realtimeArrival || loc.realtimeDeparture;
                    return (
                      <div key={lIdx} className={`relative flex items-center gap-6 md:gap-12 py-6 px-4 rounded-3xl transition-all ${isCurrent ? 'bg-blue-600/5 border border-blue-500/20 shadow-xl' : ''}`}>
                        <div className="flex flex-col items-center z-10 w-16 md:w-24 shrink-0">
                           <div className={`mono text-sm md:text-2xl font-bold tracking-widest ${isCurrent ? 'text-blue-400' : 'text-slate-500'}`}>{formatTime(time)}</div>
                           <div className={`mt-3 h-4 w-4 rounded-full border-[3px] bg-black transition-all ${isCurrent ? 'border-blue-500 scale-125 shadow-lg' : 'border-zinc-800'}`} />
                        </div>
                        <div className="flex-1 flex flex-col md:flex-row md:items-center justify-between">
                          <div>
                            <div className="flex items-center gap-4">
                              <span className={`text-xl md:text-4xl font-black uppercase tracking-tight ${isCurrent ? 'text-blue-400' : 'text-slate-200'}`}>{loc.description}</span>
                              <span className="text-[10px] font-black text-slate-700 tracking-[0.4em] bg-zinc-900 px-2 py-0.5 rounded">{loc.crs}</span>
                            </div>
                            <div className={`text-[10px] md:text-[12px] font-black uppercase tracking-[0.2em] mt-1 ${status.color}`}>{status.text} {actual && actual !== time ? `(${formatTime(actual)})` : ''}</div>
                          </div>
                          {loc.platform && <div className="text-right"><span className="text-[8px] block font-black text-slate-700 uppercase">Platform</span><span className="text-2xl font-black text-slate-200">{loc.platform}</span></div>}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
              <div className="p-8 md:p-12 flex justify-center shrink-0">
                 <button onClick={closeServiceDetail} className="px-12 py-4 bg-zinc-900 border border-zinc-800 hover:bg-white hover:text-black transition-all rounded-full font-black uppercase tracking-[0.5em] text-[10px] active:scale-95">Return to Board</button>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-10 py-5 flex justify-between items-center opacity-30 shrink-0">
         <div className="flex items-center gap-8 text-[9px] font-black uppercase tracking-[0.4em] text-zinc-600">
            <span className="flex items-center gap-2"><div className="w-1.5 h-1.5 bg-blue-600 rounded-full" /> LIVE_STREAM_ACTIVE</span>
            <span>AUTO_REFRESH: 30S</span>
         </div>
         <div className="text-[9px] font-black uppercase tracking-[0.4em] text-zinc-800">BUILD_ID: PRO_2.5.0</div>
      </footer>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        body { overflow: hidden; margin: 0; }
        .animate-in { animation: slideUp 0.6s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes slideUp { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    const saved = localStorage.getItem(RECENT_STATIONS_KEY);
    if (saved) {
      try {
        setRecentStations(JSON.parse(saved));
      } catch (e) {
        setRecentStations([]);
      }
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError(err.message || "Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) return obj.length > 0 ? getStationName(obj[obj.length - 1]) : "";
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) name = getStationName(service.locationDetail.destination);
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
      setDepartures([]);
      setSelectedService(null);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    setRecentStations(prev => {
      const filtered = prev.filter(s => s.crs !== station.crs);
      const updated = [station, ...filtered].slice(0, 12);
      localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated));
      return updated;
    });

    try {
      const data = await fetchDepartures(station.crs);
      const services = Array.isArray(data.services) ? data.services : [];
      setDepartures(services);
      setLastUpdated(new Date());

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      if (!silent) setError(err.message || "Connection error occurred.");
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
    } catch (err: any) {
      alert("Error: " + err.message);
    } finally {
      setIsServiceLoading(false);
    }
  };

  // Departure Board Refresh
  useEffect(() => {
    if (!selectedStation || selectedService) return;
    const interval = setInterval(() => loadStationData(selectedStation, true), 30000);
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, loadStationData]);

  // Journey Timeline Refresh
  useEffect(() => {
    if (!selectedService) return;
    const interval = setInterval(async () => {
      try {
        const details = await fetchServiceDetails(selectedService.serviceUid, selectedService.runDate);
        setSelectedService(details);
        setLastUpdated(new Date());
      } catch (err) {
        console.error("Refresh failed", err);
      }
    }, 30000);
    return () => clearInterval(interval);
  }, [selectedService?.serviceUid, selectedService?.runDate]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10" };

    let baseText = "On Time";
    let color = "text-emerald-400";
    let bg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      try {
        const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
        const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
        let diff = aMin - pMin;
        if (diff < -1200) diff += 1440;
        if (diff > 1200) diff -= 1440;

        if (diff > 0) {
          if (diff > 59) {
            baseText = "Delayed";
            color = "text-rose-400";
            bg = "bg-rose-400/10";
          } else {
            baseText = `${diff}m Late`;
            color = "text-orange-400";
            bg = "bg-orange-400/10";
