};

/**
 * Normalizes HHMM strings into a comparable number, 
 * handling the midnight wrap-around relative to a reference time.
 */
function getSortTime(timeStr: string, refMinutes: number): number {
  const hours = parseInt(timeStr.slice(0, 2), 10);
  const mins = parseInt(timeStr.slice(2, 4), 10);
  let totalMins = hours * 60 + mins;

  // If the time is much earlier than reference, assume it's tomorrow
  if (totalMins < refMinutes - 600) {
    totalMins += 1440; 
  }

  return totalMins;
}

export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  const timestamp = Date.now();
  const targetUrl = `https://api.rtt.io/api/v1/json/search/${crs}`;
  // Using a robust proxy wrapper with error detection
  const proxiedUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl + '?t=' + timestamp)}`;

  try {
    const response = await fetch(proxiedUrl, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      if (response.status === 401 || response.status === 403) {
        throw new Error("API Authentication failed. Please check credentials.");
      }
      if (response.status === 429) {
        throw new Error("Rate limit exceeded. Please wait a moment.");
      }
      throw new Error(`Server returned ${response.status}. The service might be temporarily unavailable.`);
    }

    const data: RTTResponse = await response.json();

    if (data.error) {
      throw new Error(`RTT API Error: ${data.error}`);
    }

    const now = new Date();
    const currentMinutes = now.getHours() * 60 + now.getMinutes();

    if (data.services && Array.isArray(data.services)) {
      // RELAXED FILTERING:
      // Instead of removing all departed trains, we only remove those that departed 
      // over 30 minutes ago to allow for system clock discrepancies.
      data.services = data.services.filter(s => {
        if (!s.locationDetail.realtimeDepartureActual) return true;

        const depTime = s.locationDetail.realtimeDeparture || s.locationDetail.gbttBookedDeparture;
        if (!depTime) return true;

        const depMins = getSortTime(depTime, currentMinutes);
        // Be very lenient: only hide if it departed more than 30 mins ago
        return (currentMinutes - depMins) <= 30;
      });

      data.services.sort((a, b) => {
        const timeA = a.locationDetail?.gbttBookedDeparture || a.locationDetail?.realtimeDeparture || "0000";
        const timeB = b.locationDetail?.gbttBookedDeparture || b.locationDetail?.realtimeDeparture || "0000";

        const sortA = getSortTime(timeA, currentMinutes);
        const sortB = getSortTime(timeB, currentMinutes);

        return sortA - sortB;
      });
    } else {
      data.services = [];
    }

    return data;
  } catch (error: any) {
    console.error('RTT Fetch Error:', error);
    if (error.name === 'TypeError') {
      throw new Error("Network error: Unable to reach the departure service. Check your internet connection.");
    }
    throw error;
  }
}

export async function fetchServiceDetails(serviceUid: string, runDate: string): Promise<ServiceDetail> {
  const timestamp = Date.now();
  const formattedDate = runDate.replace(/-/g, '/');
  const targetUrl = `https://api.rtt.io/api/v1/json/service/${serviceUid}/${formattedDate}?t=${timestamp}`;
  const proxiedUrl = `https://corsproxy.io/?${encodeURIComponent(targetUrl)}`;

  try {
    const response = await fetch(proxiedUrl, {
      method: 'GET',
      headers: {
        'Authorization': getAuthHeader(),
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Service Detail Error (${response.status})`);
    }

    return await response.json();
  } catch (error: any) {
    console.error('RTT Service Detail Error:', error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  // Connection & Retry states
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  // Handle browser online/offline status with a generous delay (20s) to accommodate patchy train Wi-Fi
  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 20000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      console.warn("LocalStorage access failed:", e);
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        retryActionRef.current();
        retryActionRef.current = null;
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError(err.message || "Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) return obj.length > 0 ? getStationName(obj[obj.length - 1]) : "";
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) name = getStationName(service.locationDetail.destination);
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);

      if (data.location?.name && !silent) {
        setSelectedStation(prev => prev ? { ...prev, name: data.location!.name } : station);
      }

      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(prev => {
        if (silent || prev.length > 0) {
          return services.map(s => {
            const match = prev.find(p => p.serviceUid === s.serviceUid);
            return match ? { ...s, callingPoints: match.callingPoints } : s;
          });
        }
        return services;
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);

      if (!silent) {
        const finalStation = { ...station, name: data.location?.name || station.name };
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== finalStation.crs);
          const updated = [finalStation, ...filtered].slice(0, 12);
          try {
            localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated));
          } catch (e) { /* Storage full or disabled */ }
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Fetch failure:", err);
      if (!silent) {
        setError(err.message || "Connection error occurred.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline && retryCountdown === null) {
          setRetryCountdown(30); 
        }
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length, isOffline, retryCountdown]);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    setError(null);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
    } catch (err: any) {
      setError("Network issue. Retrying detail view...");
      retryActionRef.current = () => handleServiceClick(service);
      if (!isOffline) setRetryCountdown(30); 
    } finally {
      setIsServiceLoading(false);
    }
  };

  useEffect(() => {
    if (!selectedStation || selectedService || retryCountdown !== null || isOffline) return;
    const interval = setInterval(() => loadStationData(selectedStation, true), 30000);
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, loadStationData, retryCountdown, isOffline]);

  useEffect(() => {
    if (!selectedService || retryCountdown !== null || isOffline) return;

    const timer = setTimeout(async () => {
      try {
        const details = await fetchServiceDetails(selectedService.serviceUid, selectedService.runDate);
        setSelectedService(details);
        setLastUpdated(new Date());
      } catch (err) {
        retryActionRef.current = () => {
          setLastUpdated(new Date());
        };
      }
    }, 30000);

    return () => clearTimeout(timer);
  }, [selectedService, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail, isFinalDestination?: boolean, allLocations?: LocationDetail[], index?: number) => {
    let planned: string | undefined;
    let actual: string | undefined;
    let prefix = "";

    let isPassed = location.realtimeDepartureActual === true;

    if (!isPassed && allLocations && index !== undefined) {
      for (let i = index + 1; i < allLocations.length; i++) {
        const futureLoc = allLocations[i];
        if (futureLoc.realtimeArrivalActual === true || futureLoc.realtimeDepartureActual === true) {
          isPassed = true;
          break;
        }
      }
    }

    const isArrivedOnly = !isPassed && location.realtimeArrivalActual === true;

    if (isPassed) {
      prefix = "Departed ";
      planned = location.gbttBookedDeparture || location.gbttBookedArrival;
      actual = location.realtimeDeparture || location.realtimeArrival;
    } else if (location.realtimeArrivalActual) {
      prefix = isFinalDestination ? "Terminated " : "Arrived ";
      planned = location.gbttBookedArrival || location.gbttBookedDeparture;
      actual = location.realtimeArrival || location.realtimeDeparture;
    } else {
      planned = location.gbttBookedDeparture || location.gbttBookedArrival;
      actual = location.realtimeDeparture || location.realtimeArrival;
    }

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted: isPassed, isArrivedOnly };

    let baseText = "On Time";
    let color = "text-emerald-400";
    let bg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      try {
        const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
        const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
        let diff = aMin - pMin;
        if (diff < -1200) diff += 1440;
        if (diff > 1200) diff -= 1440;

        if (diff > 0) {
          if (diff > 59) {
            baseText = "Delayed";
            color = "text-rose-400";
            bg = "bg-rose-400/10";
          } else {
            baseText = `${diff}m Late`;
            color = "text-orange-400";
            bg = "bg-orange-400/10";
          }
        }
      } catch (e) {
        baseText = "Live";
      }
    }

    if (isArrivedOnly && !isFinalDestination) {
      color = "text-pink-500";
      bg = "bg-pink-500/10";
    } 
    else if (isPassed || (isFinalDestination && location.realtimeArrivalActual)) {
      color = "text-orange-500";
      bg = "bg-orange-500/10";
    }

    return { 
      text: `${prefix}${baseText}`, 
      color, 
      bg, 
      isDeparted: isPassed,
      isArrived: location.realtimeArrivalActual === true,
      isArrivedOnly
    };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    const parts = dateStr.split(/[-/]/);
    return parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : dateStr;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
    setRetryCountdown(null);
    setError(null);
    setShowOfflineUI(false);
  };

  const closeServiceDetail = () => {
    setSelectedService(null);
    setRetryCountdown(null);
    setError(null);
  };

  if (!selectedStation) {
    const stationsToDisplay = recentStations.length > 0 ? recentStations : MAJOR_STATIONS.slice(0, 12);
    const stationsHeading = recentStations.length > 0 ? "Recent Terminals" : "Major Hubs";

    return (
      <div className="h-screen w-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-24 p-4 sm:p-6 bg-[#0b1120] overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-8 flex items-center justify-center gap-4">
            <div className="p-2.5 bg-blue-600 rounded-2xl text-white shadow-2xl shadow-blue-500/20"><Icons.Train /></div>
            <div className="text-left">
              <h1 className="text-2xl md:text-4xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] mt-1">Real-time Terminal</p>
            </div>
          </header>

          <div className="relative group mb-8">
            <div className="relative bg-slate-900 border border-slate-700/50 rounded-2xl p-1 shadow-2xl">
              <div className="relative flex items-center">
                <div className="absolute left-5 text-slate-500">
                  {isSearching ? <div className="animate-spin h-5 w-5 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-14 pr-6 py-4 bg-transparent text-white placeholder-slate-600 focus:outline-none text-lg md:text-xl font-bold"
                  placeholder="Find a station..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>
              {searchError && <div className="px-5 py-3 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">{searchError}</div>}
              {searchResults.length > 0 && (
                <div className="mt-1 border-t border-slate-800 max-h-64 overflow-y-auto custom-scrollbar">
                  {searchResults.map((s) => (
                    <button key={s.crs} onClick={() => loadStationData(s)} className="w-full flex items-center justify-between p-4 hover:bg-white/5 text-left transition-all group">
                      <div className="flex items-baseline gap-3">
                        <div className="font-bold text-white group-hover:text-blue-400 text-base md:text-lg">{s.name}</div>
                        <div className="text-[10px] text-slate-600 uppercase font-black tracking-widest bg-slate-800/50 px-1.5 py-0.5 rounded">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 transition-transform group-hover:translate-x-1"><Icons.ChevronRight /></div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-8">
              <div className="flex items-center gap-4 mb-5">
                <div className="h-px bg-slate-800/50 flex-1"></div>
                <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.5em]">{stationsHeading}</h3>
                <div className="h-px bg-slate-800/50 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 pb-10">
                {stationsToDisplay.map((s) => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="px-3 py-2.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-xl text-[10px] font-bold transition-all truncate text-center">
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      {(showOfflineUI || retryCountdown !== null) && (
        <div className="absolute top-16 md:top-20 left-1/2 -translate-x-1/2 z-[60] animate-in">
          <div className={`${showOfflineUI ? 'bg-zinc-800' : 'bg-rose-600/90'} backdrop-blur text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-4 border border-white/10`}>
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] leading-none mb-1">
                {showOfflineUI ? 'Offline' : 'Connection Lost'}
              </span>
              <span className="text-xs font-bold whitespace-nowrap">
                {showOfflineUI ? 'Waiting for signal...' : `Retrying in ${retryCountdown}s`}
              </span>
            </div>
            {!isOffline && (
              <button 
                onClick={() => setRetryCountdown(0)}
                className="p-2 bg-white/10 hover:bg-white/20 rounded-full transition-all active:scale-90"
                title="Retry Now"
              >
                <Icons.Refresh />
              </button>
            )}
          </div>
        </div>
      )}

      <nav className="z-50 bg-black/95 backdrop-blur-2xl border-b border-white/5 px-4 md:px-10 py-3 md:py-4 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-2 md:gap-4">
          <button onClick={resetToSearch} className="p-2 hover:bg-white/5 rounded-full text-slate-500 hover:text-white transition-all active:scale-90" title="Station Search">
            <Icons.ChevronDoubleLeft />
          </button>
          {selectedService && (
             <button onClick={closeServiceDetail} className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-all active:scale-90" title="Return to Board">
                <Icons.ChevronLeft />
             </button>
          )}
          <div className="flex flex-col ml-1 md:ml-2">
             <div className="flex items-center gap-2 mb-0.5">
                <span className="text-blue-500 font-black tracking-widest text-[10px] uppercase">{selectedStation.crs}</span>
                <span className={`w-1.5 h-1.5 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)] ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[140px] xs:max-w-[200px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-3">
           <div className="flex flex-col items-end opacity-90 hidden sm:flex mr-4 md:mr-8">
             <span className="text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-1">Live Update</span>
             <div className="mono text-emerald-400 text-sm md:text-xl font-bold tracking-[0.2em] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>
           <div className="flex items-center gap-2 md:gap-3">
             <button onClick={toggleFullscreen} className="p-2 text-slate-500 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all active:scale-90">
               {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
             </button>
             <button onClick={resetToSearch} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all active:scale-90 font-black text-[10px] uppercase tracking-widest">
               <Icons.Search /> <span className="hidden md:inline">Search</span>
             </button>
           </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-4 lg:p-6 max-w-[1800px] mx-auto w-full animate-in flex flex-col">
        <div className="flex-1 rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl flex flex-col overflow-hidden relative">

          {!selectedService && (
            <>
              <div className="grid grid-cols-12 gap-4 px-6 md:px-10 py-2.5 bg-zinc-900/30 border-b border-white/5 text-[9px] font-black uppercase tracking-[0.5em] text-zinc-500 shrink-0">
                <div className="col-span-3 md:col-span-2">Time</div>
                <div className="col-span-9 md:col-span-10">Destination</div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 ? (
                  <div className="h-full w-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase">Updating...</div>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full w-full flex flex-col items-center justify-center p-8 md:p-20 text-center">
                    <div className="text-slate-400 font-black text-2xl md:text-4xl uppercase italic tracking-tighter mb-4">No Departures</div>
                    <p className="text-slate-600 text-xs max-w-sm mb-6">There are no services currently scheduled for this terminal within the next few hours.</p>
                    {error && <div className="text-[10px] text-rose-500 font-black uppercase tracking-widest bg-rose-500/5 px-4 py-2 rounded border border-rose-500/20">{error}</div>}
                    {!error && (
                      <div className="text-[10px] text-slate-500 font-black uppercase tracking-widest opacity-50 mt-4">
                        Troubleshooting: Ensure your device clock is set to "Automatic"
                      </div>
                    )}
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destination = getFullDestinationName(service);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;

                    return (
                      <button key={`${service.serviceUid}-${idx}`} onClick={() => handleServiceClick(service)} className={`w-full text-left grid grid-cols-12 gap-3 md:gap-6 px-6 md:px-10 py-2 items-start hover:bg-white/[0.02] transition-all group border-none ${isGone ? 'opacity-80' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className={`text-3xl md:text-6xl font-black mono leading-none tracking-tighter transition-colors ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-white group-hover:text-blue-500'}`}>
                            {formatTime(service.locationDetail.gbttBookedDeparture || service.locationDetail.realtimeDeparture)}
                          </div>
                          <div className={`text-[8px] md:text-[9px] font-black uppercase tracking-[0.2em] px-1.5 py-0.5 rounded w-fit mt-1.5 ${status.bg} ${status.color}`}>
                            {status.text}
                          </div>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-3 mb-1">
                            <div className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100'}`}>{destination}</div>
                          </div>
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 min-h-[20px]">
                             {service.callingPoints ? (
                               <div className="flex items-center gap-2 overflow-hidden">
                                 <span className="text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 {service.callingPoints.map((stop, sIdx) => (
                                   <React.Fragment key={sIdx}>
                                     <span className={`text-[9px] md:text-[12px] font-medium transition-colors whitespace-nowrap ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-slate-500 group-hover:text-slate-300'}`}>{stop}</span>
                                     {sIdx < service.callingPoints!.length - 1 && <div className="w-1 h-1 bg-slate-800 rounded-full" />}
                                   </React.Fragment>
                                 ))}
                               </div>
                             ) : <span className={`text-[9px] font-black uppercase tracking-[0.4em] ${isGone ? 'text-orange-800' : isArrived ? 'text-pink-800' : 'text-zinc-700'}`}>{enriching ? 'Refreshing Stops...' : 'Direct Express'}</span>}
                             <div className="ml-auto flex items-center gap-3 hidden md:flex">
                               {service.locationDetail.platform && (
                                 <div className="flex flex-col items-end">
                                    <span className="text-[6px] font-black text-zinc-700 uppercase tracking-widest">Plat</span>
                                    <span className={`text-lg font-black ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-white'}`}>{service.locationDetail.platform}</span>
                                 </div>
                               )}
                             </div>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {selectedService && (
            <div className="flex-1 flex flex-col overflow-hidden animate-in">
              <header className="px-6 md:px-8 py-3 md:py-5 flex flex-row items-center justify-between gap-4 border-b border-white/5 bg-zinc-900/10 shrink-0">
                <div className="flex items-center gap-4 shrink-0">
                  <div className="overflow-hidden">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.4em]">{selectedService.trainIdentity}</span>
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                      <span className="text-[8px] font-bold text-zinc-600 uppercase tracking-widest border border-white/5 px-1.5 py-0.5 rounded hidden xs:inline">AUTO-REFRESH</span>
                    </div>
                    <h2 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter text-white leading-none truncate">Timeline</h2>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-[0.4em] mb-0.5">
                    Updated {lastUpdated?.toLocaleTimeString('en-GB', { hour12: false })}
                  </span>
                  <div className="text-[10px] md:text-lg font-bold text-slate-300 uppercase leading-none tracking-widest">
                    {formatDate(selectedService.runDate)}
                  </div>
                </div>
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-2 md:p-6 relative">
                <div className="max-w-3xl mx-auto space-y-1 relative pb-10">
                  <div className="absolute left-[1.95rem] md:left-[3.45rem] top-6 bottom-16 w-0.5 bg-zinc-900" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const isFinalDest = lIdx === selectedService.locations.length - 1;
                    const status = calculateStatus(loc, isFinalDest, selectedService.locations, lIdx);
                    const isCurrent = loc.crs === selectedStation?.crs;
                    const isPassed = status.isDeparted || (isFinalDest && status.isArrived);
                    const isArrivedOnly = status.isArrivedOnly;
                    const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                    const actual = loc.realtimeArrival || loc.realtimeDeparture;
                    const isSegmentPassed = isPassed && lIdx < selectedService.locations.length - 1;

                    return (
                      <div key={lIdx} className="relative">
                        {lIdx < selectedService.locations.length - 1 && (
                          <div className={`absolute left-[1.95rem] md:left-[3.45rem] top-10 h-8 w-0.5 z-0 ${isSegmentPassed ? 'bg-orange-600/40' : 'bg-blue-600/20'}`} />
                        )}
                        <div className={`relative flex items-center gap-4 md:gap-8 py-2 md:py-3 px-3 rounded-2xl transition-all z-10 ${isCurrent && !isPassed ? 'bg-blue-600/10 border border-blue-500/20 shadow-lg' : ''} ${isPassed ? 'opacity-90' : ''}`}>
                          <div className="flex flex-col items-center z-10 w-12 md:w-20 shrink-0">
                            <div className={`mono text-xs md:text-xl font-bold tracking-widest ${isCurrent && !isPassed ? 'text-blue-400' : isPassed ? 'text-orange-600' : isArrivedOnly ? 'text-pink-500' : 'text-slate-500'}`}>{formatTime(time)}</div>
                            <div className={`mt-1.5 h-3 w-3 rounded-full border-[2px] transition-all ${
                              isArrivedOnly 
                                ? 'bg-pink-500 border-pink-500 scale-125 shadow-[0_0_15px_rgba(236,72,153,0.8)]' 
                                : isCurrent && !isPassed
                                  ? 'border-blue-500 scale-110 shadow-[0_0_10px_rgba(59,130,246,0.5)] bg-black'
                                  : isPassed 
                                    ? 'border-orange-600 bg-orange-900/20' 
                                    : 'border-zinc-800 bg-black'
                            }`} />
                          </div>
                          <div className="flex-1 flex flex-row items-center justify-between">
                            <div className="flex flex-col">
                              <div className="flex items-center gap-3">
                                <span className={`text-sm md:text-2xl font-black uppercase tracking-tight ${isCurrent && !isPassed ? 'text-blue-400' : isPassed ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-slate-200'}`}>{loc.description}</span>
                                <span className={`text-[8px] font-black tracking-[0.2em] px-1 py-0.5 rounded ${isPassed ? 'text-orange-800 bg-orange-900/10' : isArrivedOnly ? 'text-pink-800 bg-pink-900/10' : 'text-slate-700 bg-zinc-900'}`}>{loc.crs}</span>
                              </div>
                              <div className={`text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] mt-0.5 inline-block w-fit px-1.5 py-0.5 rounded ${status.color} ${status.bg}`}>
                                {status.text} {actual && actual !== time ? `(${formatTime(actual)})` : ''}
                              </div>
                            </div>
                            {loc.platform && (
                              <div className="text-right">
                                <span className={`text-[6px] block font-black uppercase tracking-widest ${isPassed ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-slate-700'}`}>Plat</span>
                                <span className={`text-lg md:text-xl font-black ${isPassed ? 'text-orange-600' : isArrivedOnly ? 'text-pink-500' : 'text-slate-300'}`}>{loc.platform}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="px-8 py-3 flex justify-between items-center opacity-30 shrink-0">
         <div className="flex items-center gap-6 text-[8px] font-black uppercase tracking-[0.4em] text-zinc-600">
            <span className="flex items-center gap-1.5"><div className="w-1 h-1 bg-blue-600 rounded-full" /> LIVE_STREAM_READY</span>
            <span>DATA_SOURCE: RTT_IO</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-800">BUILD_V_2.7.6</div>
      </footer>

      <style>{`
        body { overflow: hidden; margin: 0; background-color: #000; }
        .custom-scrollbar::-webkit-scrollbar { width: 10px; height: 10px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; border: 2px solid #000; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
        .custom-scrollbar { scrollbar-width: thin; scrollbar-color: #334155 transparent; }
        .animate-in { animation: slideUp 0.5s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes slideUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @media (min-width: 400px) { .xs\\:inline { display: inline; } .xs\\:hidden { display: none; } }
        @media (max-width: 399px) { .xs\\:inline { display: none; } .xs\\:hidden { display: inline; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  // Connection & Retry states
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  // Handle browser online/offline status with a generous delay (20s) to accommodate patchy train Wi-Fi
  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 20000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      console.warn("LocalStorage access failed:", e);
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        retryActionRef.current();
        retryActionRef.current = null;
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError(err.message || "Lookup service unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getStationName = (obj: any): string => {
    if (!obj) return "";
    if (Array.isArray(obj)) return obj.length > 0 ? getStationName(obj[obj.length - 1]) : "";
    return obj.description || obj.locationName || obj.publicName || obj.name || obj.crs || "";
  };

  const getFullDestinationName = (service: Service): string => {
    let name = getStationName(service.destination);
    if (!name && service.locationDetail) name = getStationName(service.locationDetail.destination);
    return name || "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station || !station.crs) return;

    if (!silent) {
      setLoading(true);
    }

    setEnriching(false);
    setError(null);
    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);

      if (data.location?.name && !silent) {
        setSelectedStation(prev => prev ? { ...prev, name: data.location!.name } : station);
      }

      const services = Array.isArray(data.services) ? data.services : [];

      setDepartures(prev => {
        if (silent || prev.length > 0) {
          return services.map(s => {
            const match = prev.find(p => p.serviceUid === s.serviceUid);
            return match ? { ...s, callingPoints: match.callingPoints } : s;
          });
        }
        return services;
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);

      if (!silent) {
        const finalStation = { ...station, name: data.location?.name || station.name };
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== finalStation.crs);
          const updated = [finalStation, ...filtered].slice(0, 12);
          try {
            localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated));
          } catch (e) { /* Storage full or disabled */ }
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 15).map(s => ({
          origin: getStationName(s.origin) || "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Fetch failure:", err);
      if (!silent) {
        setError(err.message || "Connection error occurred.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline && retryCountdown === null) {
          setRetryCountdown(30); 
        }
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length, isOffline, retryCountdown]);

  const handleServiceClick = async (service: Service) => {
    setIsServiceLoading(true);
    setError(null);
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
    } catch (err: any) {
      setError("Network issue. Retrying detail view...");
      retryActionRef.current = () => handleServiceClick(service);
      if (!isOffline) setRetryCountdown(30); 
    } finally {
      setIsServiceLoading(false);
    }
  };

  useEffect(() => {
    if (!selectedStation || selectedService || retryCountdown !== null || isOffline) return;
    const interval = setInterval(() => loadStationData(selectedStation, true), 30000);
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, loadStationData, retryCountdown, isOffline]);

  useEffect(() => {
    if (!selectedService || retryCountdown !== null || isOffline) return;

    const timer = setTimeout(async () => {
      try {
        const details = await fetchServiceDetails(selectedService.serviceUid, selectedService.runDate);
        setSelectedService(details);
        setLastUpdated(new Date());
      } catch (err) {
        retryActionRef.current = () => {
          setLastUpdated(new Date());
        };
      }
    }, 30000);

    return () => clearTimeout(timer);
  }, [selectedService, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail, isFinalDestination?: boolean, allLocations?: LocationDetail[], index?: number) => {
    let planned: string | undefined;
    let actual: string | undefined;
    let prefix = "";

    let isPassed = location.realtimeDepartureActual === true;

    if (!isPassed && allLocations && index !== undefined) {
      for (let i = index + 1; i < allLocations.length; i++) {
        const futureLoc = allLocations[i];
        if (futureLoc.realtimeArrivalActual === true || futureLoc.realtimeDepartureActual === true) {
          isPassed = true;
          break;
        }
      }
    }

    const isArrivedOnly = !isPassed && location.realtimeArrivalActual === true;

    if (isPassed) {
      prefix = "Departed ";
      planned = location.gbttBookedDeparture || location.gbttBookedArrival;
      actual = location.realtimeDeparture || location.realtimeArrival;
    } else if (location.realtimeArrivalActual) {
      prefix = isFinalDestination ? "Terminated " : "Arrived ";
      planned = location.gbttBookedArrival || location.gbttBookedDeparture;
      actual = location.realtimeArrival || location.realtimeDeparture;
    } else {
      planned = location.gbttBookedDeparture || location.gbttBookedArrival;
      actual = location.realtimeDeparture || location.realtimeArrival;
    }

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted: isPassed, isArrivedOnly };

    let baseText = "On Time";
    let color = "text-emerald-400";
    let bg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      try {
        const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
        const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
        let diff = aMin - pMin;
        if (diff < -1200) diff += 1440;
        if (diff > 1200) diff -= 1440;

        if (diff > 0) {
          if (diff > 59) {
            baseText = "Delayed";
            color = "text-rose-400";
            bg = "bg-rose-400/10";
          } else {
            baseText = `${diff}m Late`;
            color = "text-orange-400";
            bg = "bg-orange-400/10";
          }
        }
      } catch (e) {
        baseText = "Live";
      }
    }

    if (isArrivedOnly && !isFinalDestination) {
      color = "text-pink-500";
      bg = "bg-pink-500/10";
    } 
    else if (isPassed || (isFinalDestination && location.realtimeArrivalActual)) {
      color = "text-orange-500";
      bg = "bg-orange-500/10";
    }

    return { 
      text: `${prefix}${baseText}`, 
      color, 
      bg, 
      isDeparted: isPassed,
      isArrived: location.realtimeArrivalActual === true,
      isArrivedOnly
    };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    const parts = dateStr.split(/[-/]/);
    return parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : dateStr;
  };

  const resetToSearch = () => {
    setSelectedStation(null);
    setDepartures([]);
    setSearchQuery('');
    setSearchError(null);
    setLastUpdated(null);
    setSelectedService(null);
    setRetryCountdown(null);
    setError(null);
    setShowOfflineUI(false);
  };

  const closeServiceDetail = () => {
    setSelectedService(null);
    setRetryCountdown(null);
    setError(null);
  };

  if (!selectedStation) {
    const stationsToDisplay = recentStations.length > 0 ? recentStations : MAJOR_STATIONS.slice(0, 12);
    const stationsHeading = recentStations.length > 0 ? "Recent Terminals" : "Major Hubs";

    return (
      <div className="h-screen w-screen text-slate-200 flex flex-col items-center justify-start pt-6 md:pt-24 p-4 sm:p-6 bg-[#0b1120] overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-8 flex items-center justify-center gap-4">
            <div className="p-2.5 bg-blue-600 rounded-2xl text-white shadow-2xl shadow-blue-500/20"><Icons.Train /></div>
            <div className="text-left">
              <h1 className="text-2xl md:text-4xl font-black tracking-tighter text-white italic uppercase leading-none">UK Rail Live</h1>
              <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.4em] mt-1">Real-time Terminal</p>
            </div>
          </header>

          <div className="relative group mb-8">
            <div className="relative bg-slate-900 border border-slate-700/50 rounded-2xl p-1 shadow-2xl">
              <div className="relative flex items-center">
                <div className="absolute left-5 text-slate-500">
                  {isSearching ? <div className="animate-spin h-5 w-5 border-2 border-blue-500 border-t-transparent rounded-full" /> : <Icons.Search />}
                </div>
                <input
                  type="text"
                  className="w-full pl-14 pr-6 py-4 bg-transparent text-white placeholder-slate-600 focus:outline-none text-lg md:text-xl font-bold"
                  placeholder="Find a station..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
              </div>
              {searchError && <div className="px-5 py-3 text-[10px] font-black text-rose-500 uppercase tracking-widest border-t border-slate-800 bg-rose-500/5">{searchError}</div>}
              {searchResults.length > 0 && (
                <div className="mt-1 border-t border-slate-800 max-h-64 overflow-y-auto custom-scrollbar">
                  {searchResults.map((s) => (
                    <button key={s.crs} onClick={() => loadStationData(s)} className="w-full flex items-center justify-between p-4 hover:bg-white/5 text-left transition-all group">
                      <div className="flex items-baseline gap-3">
                        <div className="font-bold text-white group-hover:text-blue-400 text-base md:text-lg">{s.name}</div>
                        <div className="text-[10px] text-slate-600 uppercase font-black tracking-widest bg-slate-800/50 px-1.5 py-0.5 rounded">{s.crs}</div>
                      </div>
                      <div className="text-slate-800 group-hover:text-blue-500 transition-transform group-hover:translate-x-1"><Icons.ChevronRight /></div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {!searchResults.length && !searchQuery && (
            <div className="mt-8">
              <div className="flex items-center gap-4 mb-5">
                <div className="h-px bg-slate-800/50 flex-1"></div>
                <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.5em]">{stationsHeading}</h3>
                <div className="h-px bg-slate-800/50 flex-1"></div>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-2 pb-10">
                {stationsToDisplay.map((s) => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="px-3 py-2.5 bg-slate-900/40 border border-slate-800/50 hover:border-blue-500/50 hover:bg-slate-800 text-slate-400 hover:text-white rounded-xl text-[10px] font-bold transition-all truncate text-center">
                    {s.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="z-50 bg-black/95 backdrop-blur-2xl border-b border-white/5 px-4 md:px-10 py-3 md:py-4 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-2 md:gap-4">
          <button onClick={resetToSearch} className="p-2 hover:bg-white/5 rounded-full text-slate-500 hover:text-white transition-all active:scale-90" title="Station Search">
            <Icons.ChevronDoubleLeft />
          </button>
          {selectedService && (
             <button onClick={closeServiceDetail} className="p-2 hover:bg-white/5 rounded-full text-slate-400 hover:text-white transition-all active:scale-90" title="Return to Board">
                <Icons.ChevronLeft />
             </button>
          )}
          <div className="flex flex-col ml-1 md:ml-2">
             <div className="flex items-center gap-2 mb-0.5">
                <span className="text-blue-500 font-black tracking-widest text-[10px] uppercase">{selectedStation.crs}</span>
                <span className={`w-1.5 h-1.5 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)] ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
             </div>
             <h1 className="text-lg md:text-2xl font-black tracking-tighter uppercase italic leading-none truncate max-w-[140px] xs:max-w-[180px] sm:max-w-none">
               {selectedService ? selectedService.trainIdentity : selectedStation.name}
             </h1>
          </div>
        </div>

        {/* Integrated Status indicator in top bar */}
        <div className="flex-1 flex justify-center px-4">
          {(showOfflineUI || retryCountdown !== null) && (
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border shadow-lg animate-in ${showOfflineUI ? 'bg-zinc-800/80 border-zinc-700' : 'bg-rose-600/80 border-white/10'}`}>
              <div className="flex flex-col items-center">
                <span className="text-[7px] md:text-[8px] font-black uppercase tracking-widest leading-none mb-0.5 text-white/70">
                  {showOfflineUI ? 'OFFLINE' : 'RETRIEVING DATA'}
                </span>
                <span className="text-[9px] md:text-xs font-bold whitespace-nowrap text-white leading-none">
                  {showOfflineUI ? 'SIGNAL LOST' : `RETRYING IN ${retryCountdown}S`}
                </span>
              </div>
              {!isOffline && retryCountdown !== null && (
                <button 
                  onClick={() => setRetryCountdown(0)}
                  className="p-1.5 bg-white/20 hover:bg-white/30 rounded-full transition-all active:scale-90 ml-1"
                  title="Refresh Now"
                >
                  <Icons.Refresh />
                </button>
              )}
            </div>
          )}
        </div>

        <div className="flex items-center gap-2 md:gap-3">
           <div className="flex flex-col items-end opacity-90 hidden sm:flex mr-4 md:mr-8">
             <span className="text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-1">Live Update</span>
             <div className="mono text-emerald-400 text-sm md:text-xl font-bold tracking-[0.2em] bg-emerald-500/5 px-2 py-0.5 rounded border border-emerald-500/10">
               {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB', { hour12: false }) : "--:--:--"}
             </div>
           </div>
           <div className="flex items-center gap-2 md:gap-3">
             <button onClick={toggleFullscreen} className="p-2 text-slate-500 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all active:scale-90">
               {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
             </button>
             <button onClick={resetToSearch} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg transition-all active:scale-90 font-black text-[10px] uppercase tracking-widest">
               <Icons.Search /> <span className="hidden md:inline">Search</span>
             </button>
           </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-4 lg:p-6 max-w-[1800px] mx-auto w-full animate-in flex flex-col">
        <div className="flex-1 rounded-xl md:rounded-2xl bg-[#0c0c0c] border border-white/5 shadow-2xl flex flex-col overflow-hidden relative">

          {!selectedService && (
            <>
              <div className="grid grid-cols-12 gap-4 px-6 md:px-10 py-2.5 bg-zinc-900/30 border-b border-white/5 text-[9px] font-black uppercase tracking-[0.5em] text-zinc-500 shrink-0">
                <div className="col-span-3 md:col-span-2">Time</div>
                <div className="col-span-9 md:col-span-10">Destination</div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 ? (
                  <div className="h-full w-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 rounded-full animate-spin" />
                    <div className="text-slate-500 font-black text-[9px] tracking-[0.4em] uppercase">Updating...</div>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full w-full flex flex-col items-center justify-center p-8 md:p-20 text-center">
                    <div className="text-slate-400 font-black text-2xl md:text-4xl uppercase italic tracking-tighter mb-4">No Departures</div>
                    <p className="text-slate-600 text-xs max-w-sm mb-6">There are no services currently scheduled for this terminal within the next few hours.</p>
                    {error && <div className="text-[10px] text-rose-500 font-black uppercase tracking-widest bg-rose-500/5 px-4 py-2 rounded border border-rose-500/20">{error}</div>}
                    {!error && (
                      <div className="text-[10px] text-slate-500 font-black uppercase tracking-widest opacity-50 mt-4">
                        Troubleshooting: Ensure your device clock is set to "Automatic"
                      </div>
                    )}
                  </div>
                ) : (
                  departures.map((service, idx) => {
                    const status = calculateStatus(service.locationDetail);
                    const destination = getFullDestinationName(service);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;

                    return (
                      <button key={`${service.serviceUid}-${idx}`} onClick={() => handleServiceClick(service)} className={`w-full text-left grid grid-cols-12 gap-3 md:gap-6 px-6 md:px-10 py-2 items-start hover:bg-white/[0.02] transition-all group border-none ${isGone ? 'opacity-80' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <div className={`text-3xl md:text-6xl font-black mono leading-none tracking-tighter transition-colors ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-white group-hover:text-blue-500'}`}>
                            {formatTime(service.locationDetail.gbttBookedDeparture || service.locationDetail.realtimeDeparture)}
                          </div>
                          <div className={`text-[8px] md:text-[9px] font-black uppercase tracking-[0.2em] px-1.5 py-0.5 rounded w-fit mt-1.5 ${status.bg} ${status.color}`}>
                            {status.text}
                          </div>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <div className="flex flex-wrap items-center gap-3 mb-1">
                            <div className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100'}`}>{destination}</div>
                          </div>
                          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 min-h-[20px]">
                             {service.callingPoints ? (
                               <div className="flex items-center gap-2 overflow-hidden">
                                 <span className="text-[8px] font-black text-slate-700 uppercase tracking-widest bg-white/5 px-1.5 py-0.5 rounded">Via:</span>
                                 {service.callingPoints.map((stop, sIdx) => (
                                   <React.Fragment key={sIdx}>
                                     <span className={`text-[9px] md:text-[12px] font-medium transition-colors whitespace-nowrap ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-slate-500 group-hover:text-slate-300'}`}>{stop}</span>
                                     {sIdx < service.callingPoints!.length - 1 && <div className="w-1 h-1 bg-slate-800 rounded-full" />}
                                   </React.Fragment>
                                 ))}
                               </div>
                             ) : <span className={`text-[9px] font-black uppercase tracking-[0.4em] ${isGone ? 'text-orange-800' : isArrived ? 'text-pink-800' : 'text-zinc-700'}`}>{enriching ? 'Refreshing Stops...' : 'Direct Express'}</span>}
                             <div className="ml-auto flex items-center gap-3 hidden md:flex">
                               {service.locationDetail.platform && (
                                 <div className="flex flex-col items-end">
                                    <span className="text-[6px] font-black text-zinc-700 uppercase tracking-widest">Plat</span>
                                    <span className={`text-lg font-black ${isGone ? 'text-orange-600' : isArrived ? 'text-pink-600' : 'text-white'}`}>{service.locationDetail.platform}</span>
                                 </div>
                               )}
                             </div>
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </>
          )}

          {selectedService && (
            <div className="flex-1 flex flex-col overflow-hidden animate-in">
              <header className="px-6 md:px-8 py-3 md:py-5 flex flex-row items-center justify-between gap-4 border-b border-white/5 bg-zinc-900/10 shrink-0">
                <div className="flex items-center gap-4 shrink-0">
                  <div className="overflow-hidden">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.4em]">{selectedService.trainIdentity}</span>
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                      <span className="text-[8px] font-bold text-zinc-600 uppercase tracking-widest border border-white/5 px-1.5 py-0.5 rounded hidden xs:inline">AUTO-REFRESH</span>
                    </div>
                    <h2 className="text-xl md:text-3xl font-black italic uppercase tracking-tighter text-white leading-none truncate">Timeline</h2>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end">
                  <span className="text-[8px] font-black text-slate-500 uppercase tracking-[0.4em] mb-0.5">
                    Updated {lastUpdated?.toLocaleTimeString('en-GB', { hour12: false })}
                  </span>
                  <div className="text-[10px] md:text-lg font-bold text-slate-300 uppercase leading-none tracking-widest">
                    {formatDate(selectedService.runDate)}
                  </div>
                </div>
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-2 md:p-6 relative">
                <div className="max-w-3xl mx-auto space-y-1 relative pb-10">
                  <div className="absolute left-[1.95rem] md:left-[3.45rem] top-6 bottom-16 w-0.5 bg-zinc-900" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const isFinalDest = lIdx === selectedService.locations.length - 1;
                    const status = calculateStatus(loc, isFinalDest, selectedService.locations, lIdx);
                    const isCurrent = loc.crs === selectedStation?.crs;
                    const isPassed = status.isDeparted || (isFinalDest && status.isArrived);
                    const isArrivedOnly = status.isArrivedOnly;
                    const time = loc.gbttBookedArrival || loc.gbttBookedDeparture;
                    const actual = loc.realtimeArrival || loc.realtimeDeparture;
                    const isSegmentPassed = isPassed && lIdx < selectedService.locations.length - 1;

                    return (
                      <div key={lIdx} className="relative">
                        {lIdx < selectedService.locations.length - 1 && (
                          <div className={`absolute left-[1.95rem] md:left-[3.45rem] top-10 h-8 w-0.5 z-0 ${isSegmentPassed ? 'bg-orange-600/40' : 'bg-blue-600/20'}`} />
                        )}
                        <div className={`relative flex items-center gap-4 md:gap-8 py-2 md:py-3 px-3 rounded-2xl transition-all z-10 ${isCurrent && !isPassed ? 'bg-blue-600/10 border border-blue-500/20 shadow-lg' : ''} ${isPassed ? 'opacity-90' : ''}`}>
                          <div className="flex flex-col items-center z-10 w-12 md:w-20 shrink-0">
                            <div className={`mono text-xs md:text-xl font-bold tracking-widest ${isCurrent && !isPassed ? 'text-blue-400' : isPassed ? 'text-orange-600' : isArrivedOnly ? 'text-pink-500' : 'text-slate-500'}`}>{formatTime(time)}</div>
                            <div className={`mt-1.5 h-3 w-3 rounded-full border-[2px] transition-all ${
                              isArrivedOnly 
                                ? 'bg-pink-500 border-pink-500 scale-125 shadow-[0_0_15px_rgba(236,72,153,0.8)]' 
                                : isCurrent && !isPassed
                                  ? 'border-blue-500 scale-110 shadow-[0_0_10px_rgba(59,130,246,0.5)] bg-black'
                                  : isPassed 
                                    ? 'border-orange-600 bg-orange-900/20' 
                                    : 'border-zinc-800 bg-black'
                            }`} />
                          </div>
                          <div className="flex-1 flex flex-row items-center justify-between">
                            <div className="flex flex-col">
                              <div className="flex items-center gap-3">
