          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/50 border-b border-white/5 flex items-center justify-between shrink-0">
                <button onClick={() => setSelectedService(null)} className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-500 hover:text-white transition-colors bg-white/5 px-3 py-1.5 rounded-lg">
                  <Icons.ChevronLeft /> Back to Board
                </button>
                <div className="flex flex-col items-end">
                  <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{selectedService.trainIdentity}</span>
                  <span className="text-[8px] font-bold text-zinc-600">{selectedService.atocName}</span>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-3xl mx-auto space-y-4 relative">
                  <div className="absolute left-[27px] top-6 bottom-6 w-px bg-zinc-900" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const isArrived = loc.realtimeArrivalActual || loc.realtimeDepartureActual;
                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 ${isArrived ? 'opacity-50' : ''}`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isArrived ? 'text-zinc-600' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 bg-black ${isArrived ? 'border-zinc-800' : 'border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.4)]'}`} />
                        </div>
                        <div className="flex-1 pb-4">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight ${isArrived ? 'text-zinc-500' : 'text-white'}`}>
                              {loc.description}
