                          <div className="flex items-center gap-3 mt-1">
                            <span className={`text-[10px] uppercase font-bold ${isArrived ? 'text-emerald-900' : 'text-zinc-500'}`}>
                              {isArrived ? 'SERVICE PASSED' : 'EXPECTED'}
                            </span>
                            {loc.platform && (
                              <span className="text-[10px] text-blue-500/80 font-black">PLATFORM {loc.platform}</span>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
