                                <span className={`text-lg md:text-xl font-black ${isPassed ? 'text-orange-600' : isArrivedOnly ? 'text-pink-500' : 'text-slate-300'}`}>{loc.platform}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
