            <span>DATA_SOURCE: RTT_IO</span>
         </div>
         <div className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-800">BUILD_V_2.8.0</div>
      </footer>

      <style>{`
        body { overflow: hidden; margin: 0; }
        .custom-scrollbar::-webkit-scrollbar { width: 10px; height: 10px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; border: 2px solid #000; }
