                <span className="text-[9px] font-bold text-white whitespace-nowrap">
                  {showOfflineUI ? 'SIGNAL LOST' : retryCountdown !== null ? `RETRYING ${retryCountdown}S` : 'FETCHING...'}
                </span>
              </div>
              {!isOffline && retryCountdown !== null && (
                <button onClick={() => setRetryCountdown(0)} className="p-1 hover:bg-white/20 rounded-full transition-all active:scale-95 ml-1">
                  <Icons.Refresh />
