              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative">
                  <div className="absolute left-[29px] top-4 bottom-4 w-px bg-zinc-900" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const isPassed = loc.realtimeArrivalActual || loc.realtimeDepartureActual;
                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity ${isPassed ? 'opacity-40' : ''}`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className="mono text-xs font-bold text-slate-500">{formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}</span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 bg-black ${isPassed ? 'border-zinc-800' : 'border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'}`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className="text-lg md:text-xl font-black uppercase tracking-tight text-white">{loc.description}</span>
                            <span className="text-[8px] font-black bg-white/5 px-1.5 py-0.5 rounded text-zinc-700 tracking-widest">{loc.crs}</span>
                          </div>
                          <div className="text-[10px] text-zinc-500 uppercase font-bold mt-1 flex gap-3">
                            <span>{isPassed ? 'PASSED' : 'EXPECTED'}</span>
                            {loc.platform && <span className="text-blue-500/60">PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'OFFLINE_REDUNDANCY_MODE' : 'FEED_SYNCHRONIZED'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_2.8.2_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

