import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 10000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        const action = retryActionRef.current;
        retryActionRef.current = null;
        action();
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [isOffline]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
        retryActionRef.current = () => handleServiceClick(service);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [isOffline]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    if (isOffline || retryCountdown !== null) return;

    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full overflow-hidden block">
              <div className="truncate">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white hidden md:block" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
              {loading && departures.length === 0 && !error ? (
                <div className="h-full flex flex-col items-center justify-center gap-4">
                  <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                  <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                </div>
              ) : departures.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                  <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                  <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                    {error || "We're currently unable to retrieve departures. The API may be rate-limited or the selected station is inactive."}
                  </p>
                  <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                    Attempt Refresh
                  </button>
                </div>
              ) : (
                departures.map((s, idx) => {
                  const status = calculateStatus(s.locationDetail);
                  const isGone = status.isDeparted;
                  const isArrived = status.isArrivedOnly;
                  const dest = getFullDestinationName(s);

                  return (
                    <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                      <div className="col-span-3 md:col-span-2 flex flex-col">
                        <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                          {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                        </span>
                        <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                          {status.text}
                        </span>
                      </div>
                      <div className="col-span-9 md:col-span-10">
                        <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                          {dest}
                        </h3>
                        <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                          {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                            <React.Fragment key={pIdx}>
                              <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                {p}
                              </span>
                              {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                            </React.Fragment>
                          )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                        </div>
                      </div>
                    </button>
                  );
                })
              )}
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-xs font-black text-blue-500 uppercase tracking-widest">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-24">
                  <div className="absolute left-[29px] top-4 bottom-24 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'LINK_BROKEN' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_2.9.8_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 10000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        const action = retryActionRef.current;
        retryActionRef.current = null;
        action();
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [isOffline]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
        retryActionRef.current = () => handleServiceClick(service);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [isOffline]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    if (isOffline || retryCountdown !== null) return;

    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full overflow-hidden block">
              <div className="truncate">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white hidden md:block" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
              {loading && departures.length === 0 && !error ? (
                <div className="h-full flex flex-col items-center justify-center gap-4">
                  <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                  <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                </div>
              ) : departures.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                  <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                  <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                    {error || "We're currently unable to retrieve departures. The API may be rate-limited or the selected station is inactive."}
                  </p>
                  <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                    Attempt Refresh
                  </button>
                </div>
              ) : (
                departures.map((s, idx) => {
                  const status = calculateStatus(s.locationDetail);
                  const isGone = status.isDeparted;
                  const isArrived = status.isArrivedOnly;
                  const dest = getFullDestinationName(s);

                  return (
                    <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                      <div className="col-span-3 md:col-span-2 flex flex-col">
                        <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                          {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                        </span>
                        <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                          {status.text}
                        </span>
                      </div>
                      <div className="col-span-9 md:col-span-10">
                        <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                          {dest}
                        </h3>
                        <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                          {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                            <React.Fragment key={pIdx}>
                              <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                {p}
                              </span>
                              {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                            </React.Fragment>
                          )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                        </div>
                      </div>
                    </button>
                  );
                })
              )}
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                  <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'LINK_BROKEN' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_2.9.9_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 10000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        const action = retryActionRef.current;
        retryActionRef.current = null;
        action();
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [isOffline]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
        retryActionRef.current = () => handleServiceClick(service);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [isOffline]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    if (isOffline || retryCountdown !== null) return;

    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white hidden md:block" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
              {loading && departures.length === 0 && !error ? (
                <div className="h-full flex flex-col items-center justify-center gap-4">
                  <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                  <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                </div>
              ) : departures.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                  <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                  <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                    {error || "We're currently unable to retrieve departures. The API may be rate-limited or the selected station is inactive."}
                  </p>
                  <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                    Attempt Refresh
                  </button>
                </div>
              ) : (
                departures.map((s, idx) => {
                  const status = calculateStatus(s.locationDetail);
                  const isGone = status.isDeparted;
                  const isArrived = status.isArrivedOnly;
                  const dest = getFullDestinationName(s);

                  return (
                    <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                      <div className="col-span-3 md:col-span-2 flex flex-col">
                        <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                          {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                        </span>
                        <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                          {status.text}
                        </span>
                      </div>
                      <div className="col-span-9 md:col-span-10">
                        <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 pr-4 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                          {dest}
                        </h3>
                        <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                          {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                            <React.Fragment key={pIdx}>
                              <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                {p}
                              </span>
                              {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                            </React.Fragment>
                          )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                        </div>
                      </div>
                    </button>
                  );
                })
              )}
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                  <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'LINK_BROKEN' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.0_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [showOfflineUI, setShowOfflineUI] = useState(false);
  const [retryCountdown, setRetryCountdown] = useState<number | null>(null);
  const retryActionRef = useRef<(() => void) | null>(null);

  const latestQueryRef = useRef('');

  useEffect(() => {
    let offlineTimer: number;

    const handleOnline = () => {
      window.clearTimeout(offlineTimer);
      setIsOffline(false);
      setShowOfflineUI(false);
      setError(null);
      if (retryActionRef.current) {
        setRetryCountdown(null);
        retryActionRef.current();
        retryActionRef.current = null;
      }
    };

    const handleOffline = () => {
      setIsOffline(true);
      offlineTimer = window.setTimeout(() => {
        setShowOfflineUI(true);
      }, 10000);
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.clearTimeout(offlineTimer);
    };
  }, []);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  useEffect(() => {
    if (retryCountdown === null || isOffline) return;

    if (retryCountdown <= 0) {
      setRetryCountdown(null);
      if (retryActionRef.current) {
        const action = retryActionRef.current;
        retryActionRef.current = null;
        action();
      }
      return;
    }

    const timer = setInterval(() => {
      setRetryCountdown(prev => (prev !== null ? prev - 1 : null));
    }, 1000);

    return () => clearInterval(timer);
  }, [retryCountdown, isOffline]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
        retryActionRef.current = () => loadStationData(station, true);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [isOffline]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setRetryCountdown(null);
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
        retryActionRef.current = () => handleServiceClick(service);
        if (!isOffline) setRetryCountdown(15); 
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [isOffline]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    if (isOffline || retryCountdown !== null) return;

    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData, retryCountdown, isOffline]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white hidden md:block" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Departure Board</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">Live Passenger Feed</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                    <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                    <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                      {error || "We're currently unable to retrieve departures. The API may be rate-limited or the selected station is inactive."}
                    </p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                      Attempt Refresh
                    </button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;
                    const dest = getFullDestinationName(s);

                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 pr-4 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                            {dest}
                          </h3>
                          <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                            {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                  {p}
                                </span>
                                {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                  <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isOffline ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isOffline ? 'LINK_BROKEN' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.1_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, []);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className="w-1.5 h-1.5 rounded-full animate-pulse shrink-0 bg-emerald-500" />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white hidden md:block" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Departure Board</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">Live Passenger Feed</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                    <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                    <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                      {error || "We're currently unable to retrieve departures."}
                    </p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                      Attempt Refresh
                    </button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;
                    const dest = getFullDestinationName(s);

                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 pr-4 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                            {dest}
                          </h3>
                          <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                            {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                  {p}
                                </span>
                                {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                  <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className="w-1 h-1 rounded-full bg-emerald-500" />
          CONNECTED_STREAM
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.2_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setError(null);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      if (!silent) {
        setError(err.message || "Establishing feed failed.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, []);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
    } catch (err: any) {
      if (!silent) {
        setError("Timeline extraction failed.");
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, []);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl" title="Toggle Fullscreen">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className="w-1.5 h-1.5 rounded-full animate-pulse shrink-0 bg-emerald-500" />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className="text-[7px] md:text-[8px] font-black text-emerald-500/40 uppercase tracking-[0.4em] mb-0.5 md:mb-1">Last Feed</span>
            <span className="mono text-xs md:text-lg font-bold text-emerald-400 tracking-wider">
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Departure Board</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">Live Passenger Feed</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                  </div>
                ) : departures.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                    <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                    <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                      {error || "We're currently unable to retrieve departures."}
                    </p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                      Attempt Refresh
                    </button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;
                    const dest = getFullDestinationName(s);

                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 pr-4 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                            {dest}
                          </h3>
                          <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                            {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                  {p}
                                </span>
                                {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                  <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                  {selectedService.locations.map((loc, lIdx) => {
                    const status = calculateStatus(loc);
                    const isFinalStop = lIdx === selectedService.locations.length - 1;

                    const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                    const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                    return (
                      <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                        <div className="flex flex-col items-center w-14 shrink-0">
                          <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                            {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                          </span>
                          <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                            isArrivedOnly 
                              ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                              : isDeparted 
                                ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                          }`} />
                        </div>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                              {loc.description}
                            </span>
                            <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                              {loc.crs}
                            </span>
                          </div>
                          <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                            <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                              {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                              {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                            </span>
                            {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className="w-1 h-1 rounded-full bg-emerald-500" />
          CONNECTED_STREAM
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.3_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isRefreshError, setIsRefreshError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      // Only clear hard error if we have no departures to show
      if (departures.length === 0) setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      setIsRefreshError(true);
      // Only set error screen if we have no departures at all
      if (departures.length === 0) {
        setError(err.message || "Establishing feed failed.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      if (!selectedService) setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);
    } catch (err: any) {
      console.error("Timeline extraction error:", err);
      setIsRefreshError(true);
      if (!selectedService) {
        setError("Timeline extraction failed.");
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [selectedService]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl" title="Toggle Fullscreen">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isRefreshError ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-[0.4em] mb-0.5 md:mb-1 ${isRefreshError ? 'text-rose-500/40' : 'text-emerald-500/40'}`}>
              {isRefreshError ? 'STALE DATA' : 'LAST FEED'}
            </span>
            <span className={`mono text-xs md:text-lg font-bold tracking-wider transition-colors ${isRefreshError ? 'text-rose-500' : 'text-emerald-400'}`}>
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Departure Board</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">Live Passenger Feed</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                  </div>
                ) : (departures.length === 0 && error) ? (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                    <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                    <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                      {error || "We're currently unable to retrieve departures."}
                    </p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                      Attempt Refresh
                    </button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;
                    const dest = getFullDestinationName(s);

                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-4 md:p-6 grid grid-cols-12 gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col">
                          <span className={`text-3xl md:text-5xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[8px] md:text-[9px] font-black uppercase px-2 py-0.5 mt-2 rounded w-fit ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10">
                          <h3 className={`text-xl md:text-4xl font-black uppercase tracking-tighter leading-none mb-2 pr-4 ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                            {dest}
                          </h3>
                          <div className="flex flex-wrap gap-x-3 gap-y-1 overflow-hidden min-h-[1.5rem]">
                            {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[10px] md:text-xs font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                  {p}
                                </span>
                                {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[8px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[9px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                {(!selectedService.locations && error) ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <p className="text-xs text-zinc-500 mb-4">{error}</p>
                    <button onClick={handleManualRefresh} className="text-blue-500 font-bold uppercase text-[10px]">Retry</button>
                  </div>
                ) : (
                  <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                    <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                    {selectedService.locations.map((loc, lIdx) => {
                      const status = calculateStatus(loc);
                      const isFinalStop = lIdx === selectedService.locations.length - 1;

                      const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                      const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                      return (
                        <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                          <div className="flex flex-col items-center w-14 shrink-0">
                            <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                              {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                            </span>
                            <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                              isArrivedOnly 
                                ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                                : isDeparted 
                                  ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                  : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                            }`} />
                          </div>
                          <div className="flex-1">
                            <div className="flex items-center gap-3">
                              <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                                {loc.description}
                              </span>
                              <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                                {loc.crs}
                              </span>
                            </div>
                            <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                              <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                                {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                                {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                              </span>
                              {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isRefreshError ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isRefreshError ? 'STALE_DATA_SYNC' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.4_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isRefreshError, setIsRefreshError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      if (departures.length === 0) setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      setIsRefreshError(true);
      if (departures.length === 0) {
        setError(err.message || "Establishing feed failed.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      if (!selectedService) setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);
    } catch (err: any) {
      console.error("Timeline extraction error:", err);
      setIsRefreshError(true);
      if (!selectedService) {
        setError("Timeline extraction failed.");
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [selectedService]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl" title="Toggle Fullscreen">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-20 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isRefreshError ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-lg md:text-xl font-black uppercase italic tracking-tighter leading-none w-full block">
              <div className="truncate pr-6">{selectedService ? getFullDestinationName(selectedService) : selectedStation.name}</div>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-[0.4em] mb-0.5 md:mb-1 ${isRefreshError ? 'text-rose-500/40' : 'text-emerald-500/40'}`}>
              {isRefreshError ? 'STALE DATA' : 'LAST FEED'}
            </span>
            <span className={`mono text-xs md:text-lg font-bold tracking-wider transition-colors ${isRefreshError ? 'text-rose-500' : 'text-emerald-400'}`}>
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all active:scale-90 ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`} title="Manual Refresh">
              <Icons.Refresh />
            </button>
            <button onClick={toggleFullscreen} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all" title="Toggle Fullscreen">
              {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-2 md:p-6 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="p-3 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Departure Board</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">Live Passenger Feed</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-12 w-12 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Data Pipeline...</span>
                  </div>
                ) : (departures.length === 0 && error) ? (
                  <div className="h-full flex flex-col items-center justify-center p-12 text-center">
                    <div className="text-4xl font-black italic uppercase text-zinc-800 mb-4 leading-none">System Idle</div>
                    <p className="text-xs text-zinc-500 max-w-sm mb-8 leading-relaxed">
                      {error || "We're currently unable to retrieve departures."}
                    </p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-black uppercase tracking-widest text-[10px] rounded-xl transition-all active:scale-95 shadow-lg shadow-blue-500/20">
                      Attempt Refresh
                    </button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const isArrived = status.isArrivedOnly;
                    const dest = getFullDestinationName(s);

                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full p-2 md:p-3 grid grid-cols-12 gap-2 md:gap-4 hover:bg-white/[0.02] transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col justify-center">
                          <span className={`text-2xl md:text-3xl font-black mono tracking-tighter transition-colors ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[7px] md:text-[8px] font-black uppercase px-1.5 py-0.5 mt-1 rounded w-fit ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10 flex flex-col justify-center">
                          <h3 className={`text-lg md:text-2xl font-black uppercase tracking-tighter leading-none mb-0.5 pr-4 truncate ${isGone ? 'text-orange-500' : isArrived ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>
                            {dest}
                          </h3>
                          <div className="flex flex-wrap gap-x-2 gap-y-0.5 overflow-hidden max-h-[1.2rem]">
                            {s.callingPoints ? s.callingPoints.map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[9px] md:text-[10px] font-medium whitespace-nowrap group-hover:text-slate-300 transition-colors ${isGone ? 'text-orange-600/70' : isArrived ? 'text-pink-600/70' : 'text-slate-500'}`}>
                                  {p}
                                </span>
                                {pIdx < s.callingPoints!.length - 1 && <span className="text-zinc-800 text-[7px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[8px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT SERVICE'}</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="p-4 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <div className="flex flex-col">
                  <span className="text-sm font-bold text-blue-500 tracking-tight">Journey Timeline</span>
                </div>
                <div className="text-right">
                  <div className="text-[8px] font-bold text-zinc-600 uppercase">{selectedService.atocName}</div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                {(!selectedService.locations && error) ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <p className="text-xs text-zinc-500 mb-4">{error}</p>
                    <button onClick={handleManualRefresh} className="text-blue-500 font-bold uppercase text-[10px]">Retry</button>
                  </div>
                ) : (
                  <div className="max-w-2xl mx-auto space-y-6 relative pb-32">
                    <div className="absolute left-[29px] top-4 bottom-32 w-px bg-zinc-900/50" />
                    {selectedService.locations.map((loc, lIdx) => {
                      const status = calculateStatus(loc);
                      const isFinalStop = lIdx === selectedService.locations.length - 1;

                      const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                      const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                      return (
                        <div key={lIdx} className={`flex gap-6 items-start relative z-10 transition-opacity`}>
                          <div className="flex flex-col items-center w-14 shrink-0">
                            <span className={`mono text-xs font-bold ${isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                              {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                            </span>
                            <div className={`w-3 h-3 rounded-full border-2 mt-2 transition-all duration-500 ${
                              isArrivedOnly 
                                ? 'bg-pink-500 border-pink-500 shadow-[0_0_12px_rgba(236,72,153,0.8)] scale-110 animate-pulse' 
                                : isDeparted 
                                  ? 'bg-black border-orange-500 shadow-[0_0_12px_rgba(249,115,22,0.2)]' 
                                  : 'bg-black border-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]'
                            }`} />
                          </div>
                          <div className="flex-1">
                            <div className="flex items-center gap-3">
                              <span className={`text-lg md:text-xl font-black uppercase tracking-tight transition-colors pr-4 ${isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>
                                {loc.description}
                              </span>
                              <span className={`text-[8px] font-black px-1.5 py-0.5 rounded tracking-widest transition-colors ${isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>
                                {loc.crs}
                              </span>
                            </div>
                            <div className={`text-[10px] uppercase font-bold mt-1 flex gap-3 transition-colors ${isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                              <span className={`px-2 py-0.5 rounded ${status.bg} ${status.color}`}>
                                {isDeparted ? 'VISITED' : isArrivedOnly ? 'ARRIVED' : status.displayStatus.toUpperCase()}
                                {(isDeparted || isArrivedOnly) && status.displayStatus !== "On Time" ? ` (${status.displayStatus.toUpperCase()})` : ""}
                              </span>
                              {loc.platform && <span className={`${isDeparted ? 'text-orange-600/50' : isArrivedOnly ? 'text-pink-600/50' : 'text-blue-500/60'}`}>PLAT {loc.platform}</span>}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </main>

      <footer className="h-10 border-t border-white/5 px-8 flex items-center justify-between opacity-20 shrink-0">
        <span className="text-[8px] font-black uppercase tracking-widest flex items-center gap-2">
          <div className={`w-1 h-1 rounded-full ${isRefreshError ? 'bg-rose-500' : 'bg-emerald-500'}`} />
          {isRefreshError ? 'STALE_DATA_SYNC' : 'CONNECTED_STREAM'}
        </span>
        <span className="text-[8px] font-black uppercase tracking-widest text-zinc-800">BUILD_V_3.0.5_STABLE</span>
      </footer>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1a1a1a; border-radius: 10px; }
        .animate-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, RTTResponse, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isRefreshError, setIsRefreshError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) {
        setRecentStations(JSON.parse(saved));
      }
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) {
             setSearchError("No stations found");
          }
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) {
          setSearchError("Lookup Unavailable");
        }
      } finally {
        if (latestQueryRef.current === searchQuery) {
          setIsSearching(false);
        }
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const getFullDestinationName = (service: Service | ServiceDetail): string => {
    if ('destination' in service && Array.isArray(service.destination)) {
      return service.destination[0]?.description || "Unknown Destination";
    }
    if ('locationDetail' in service) {
      const dest = service.destination || service.locationDetail?.destination;
      if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
      return dest?.description || "Check Board";
    }
    return "Check Board";
  };

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;

    if (!silent) {
      setLoading(true);
      if (departures.length === 0) setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => {
        return services.map(s => {
          const match = prev.find(p => p.serviceUid === s.serviceUid);
          return match ? { ...s, callingPoints: match.callingPoints } : s;
        });
      });

      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || 
              destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      console.error("Board sync failure:", err);
      setIsRefreshError(true);
      if (departures.length === 0) {
        setError(err.message || "Establishing feed failed.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      if (!selectedService) setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);
    } catch (err: any) {
      console.error("Timeline extraction error:", err);
      setIsRefreshError(true);
      if (!selectedService) {
        setError("Timeline extraction failed.");
      }
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [selectedService]);

  const handleManualRefresh = () => {
    if (selectedService) {
      handleServiceClick(selectedService, false);
    } else if (selectedStation) {
      loadStationData(selectedStation, false);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) {
        handleServiceClick(selectedService, true);
      } else if (selectedStation) {
        loadStationData(selectedStation, true);
      }
    }, 30000);

    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  const calculateStatus = (location: LocationDetail) => {
    const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
    const actual = location.realtimeDeparture || location.realtimeArrival;
    const isDeparted = location.realtimeDepartureActual === true;
    const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

    if (!planned) return { text: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly };

    let diffText = "On Time";
    let statusColor = "text-emerald-400";
    let statusBg = "bg-emerald-400/10";

    if (actual && actual !== planned) {
      const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
      const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
      let diff = aMin - pMin;
      if (diff < -1200) diff += 1440;
      if (diff > 1200) diff -= 1440;

      if (diff > 0) {
        diffText = `${diff}m Late`;
        statusColor = "text-rose-400";
        statusBg = "bg-rose-400/10";
      } else if (diff < 0) {
        diffText = "Early";
        statusColor = "text-emerald-400";
        statusBg = "bg-emerald-400/10";
      }
    }

    if (isDeparted) {
        return { text: "Departed", displayStatus: diffText, color: "text-orange-500", bg: "bg-orange-500/10", isDeparted, isArrivedOnly };
    }
    if (isArrivedOnly) {
        return { text: "At Station", displayStatus: diffText, color: "text-pink-500", bg: "bg-pink-500/10", isDeparted, isArrivedOnly };
    }

    return { text: diffText, displayStatus: diffText, color: statusColor, bg: statusBg, isDeparted, isArrivedOnly };
  };

  const formatTime = (timeStr?: string) => {
    if (!timeStr || timeStr.length < 4) return "--:--";
    return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
  };

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl" title="Toggle Fullscreen">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-16 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors shrink-0" title="Home">
              <Icons.ChevronDoubleLeft />
            </button>
            {selectedService && (
              <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors shrink-0" title="Return Board">
                <Icons.ChevronLeft />
              </button>
            )}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
