function getSortTime(timeStr: string, refMinutes: number): number {
  const hours = parseInt(timeStr.slice(0, 2), 10);
  const mins = parseInt(timeStr.slice(2, 4), 10);
  let totalMins = hours * 60 + mins;
  if (totalMins < refMinutes - 120) totalMins += 1440; 
  return totalMins;
}

/**
 * Resilient fetcher that cycles through functional proxies.
 * Uses AbortController for wide browser compatibility instead of AbortSignal.timeout.
 */
async function fetchSecure(targetUrl: string): Promise<Response> {
  const auth = getAuthHeader();
  const timestamp = Date.now();
  const urlWithBuster = `${targetUrl}${targetUrl.includes('?') ? '&' : '?'}_=${timestamp}`;

  const proxyConfigs = [
    { name: 'CorsProxyIO', url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` },
    { name: 'Codetabs', url: (u: string) => `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(u)}` },
    { name: 'AllOrigins', url: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` }
  ];

  let lastError: any = null;

  for (const proxy of proxyConfigs) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000);

    try {
      const finalUrl = proxy.url(urlWithBuster);
      const response = await fetch(finalUrl, {
        method: 'GET',
        headers: { 
          'Authorization': auth, 
          'Accept': 'application/json' 
        },
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (response.ok) return response;

      if (response.status === 401 || response.status === 403) {
        throw new Error("RTT API: Access Denied (Check Credentials)");
      }

      if (response.status === 429) {
        throw new Error("RTT API: Rate Limited");
      }

      throw new Error(`Proxy ${proxy.name} returned ${response.status}`);
    } catch (e: any) {
      clearTimeout(timeoutId);
      lastError = e;
      console.warn(`Connection via ${proxy.name} failed:`, e.message);
      // If it's a credentials error, don't bother trying other proxies
      if (e.message.includes("Access Denied")) throw e;
    }
  }

  throw new Error(lastError?.message || "All connection paths failed. Please check your internet or try again later.");
}

export async function fetchDepartures(crs: string): Promise<RTTResponse> {
  const targetUrl = `https://api.rtt.io/api/v1/json/search/${crs}`;

  try {
    const response = await fetchSecure(targetUrl);
    const data: RTTResponse = await response.json();

    if (data.error) throw new Error(`RTT Error: ${data.error}`);

    const now = new Date();
    const currentMinutes = now.getHours() * 60 + now.getMinutes();

    if (data.services && Array.isArray(data.services)) {
      data.services = data.services.filter(s => {
        if (!s.locationDetail.realtimeDepartureActual) return true;
        const depTime = s.locationDetail.realtimeDeparture || s.locationDetail.gbttBookedDeparture;
        if (!depTime) return true;
        const depMins = getSortTime(depTime, currentMinutes);
        return (currentMinutes - depMins) <= 15;
      });

      data.services.sort((a, b) => {
        const timeA = a.locationDetail?.gbttBookedDeparture || a.locationDetail?.realtimeDeparture || "0000";
        const timeB = b.locationDetail?.gbttBookedDeparture || b.locationDetail?.realtimeDeparture || "0000";
        return getSortTime(timeA, currentMinutes) - getSortTime(timeB, currentMinutes);
      });
    } else {
      data.services = [];
    }

    return data;
  } catch (error: any) {
    console.error('Fetch Departures Error:', error);
    throw error;
  }
}

export async function fetchServiceDetails(serviceUid: string, runDate: string): Promise<ServiceDetail> {
  const formattedDate = runDate.replace(/-/g, '/');
  const targetUrl = `https://api.rtt.io/api/v1/json/service/${serviceUid}/${formattedDate}`;

  try {
    const response = await fetchSecure(targetUrl);
    return await response.json();
  } catch (error: any) {
    console.error('Service Detail Error:', error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

// Helper functions moved out to prevent re-allocation on every render
const formatTime = (timeStr?: string) => {
  if (!timeStr || timeStr.length < 4) return "--:--";
  return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
};

const calculateStatus = (location: LocationDetail) => {
  const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
  const actual = location.realtimeDeparture || location.realtimeArrival;
  const isDeparted = location.realtimeDepartureActual === true;
  const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

  // Check for cancelled stop/skip-stopping
  if (location.displayAs === 'CANCELLED_CALL') {
    return { 
      text: "STOP CANCELLED", 
      displayStatus: "CANCELLED", 
      color: "text-rose-500", 
      bg: "bg-rose-500/20", 
      isDeparted: false, 
      isArrivedOnly: false,
      isCancelled: true 
    };
  }

  if (!planned) return { text: "Scheduled", displayStatus: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly, isCancelled: false };

  let diffText = "On Time";
  let statusColor = "text-emerald-400";
  let statusBg = "bg-emerald-400/10";

  if (actual && actual !== planned) {
    const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
    const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
    const estTime = formatTime(actual);
    let diff = aMin - pMin;
    if (diff < -1200) diff += 1440;
    if (diff > 1200) diff -= 1440;

    if (diff > 0) {
      diffText = `${diff}m Late (${estTime})`;
      statusColor = "text-rose-400";
      statusBg = "bg-rose-400/10";
    } else if (diff < 0) {
      diffText = `Early (${estTime})`;
      statusColor = "text-emerald-400";
      statusBg = "bg-emerald-400/10";
    }
  }

  return { 
    text: isDeparted ? "Departed" : isArrivedOnly ? "At Station" : diffText, 
    displayStatus: diffText, 
    color: statusColor, 
    bg: statusBg, 
    isDeparted, 
    isArrivedOnly,
    isCancelled: false
  };
};

const getFullDestinationName = (service: Service | ServiceDetail): string => {
  const dest = 'locationDetail' in service 
    ? (service.destination || service.locationDetail?.destination) 
    : (service.destination || null);

  if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
  return (dest as any)?.description || "Check Board";
};

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isRefreshError, setIsRefreshError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) setRecentStations(JSON.parse(saved));
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) setSearchError("No stations found");
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) setSearchError("Lookup Unavailable");
      } finally {
        if (latestQueryRef.current === searchQuery) setIsSearching(false);
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;
    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => services.map(s => {
        const match = prev.find(p => p.serviceUid === s.serviceUid);
        return match ? { ...s, callingPoints: match.callingPoints } : s;
      }));

      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      setIsRefreshError(true);
      if (departures.length === 0 || !silent) {
        setError(err.message || "Failed to connect to data stream.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);
    } catch (err: any) {
      setIsRefreshError(true);
      if (!selectedService || !silent) setError(err.message || "Timeline failed.");
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [selectedService]);

  const handleManualRefresh = () => {
    if (selectedService) handleServiceClick(selectedService, false);
    else if (selectedStation) loadStationData(selectedStation, false);
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchResults.length > 0) {
      loadStationData(searchResults[0]);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) handleServiceClick(selectedService, true);
      else if (selectedStation) loadStationData(selectedStation, true);
    }, 30000);
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <form onSubmit={handleSearchSubmit} className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
              {searchQuery.length > 0 && (
                <button type="submit" className="ml-2 p-2 text-blue-500 hover:text-blue-400 transition-colors">
                  <Icons.ChevronRight />
                </button>
              )}
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button type="button" key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group text-left">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </form>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

