/**
 * Highly resilient fetcher designed for mobile browser compatibility.
 * It rotates through known reliable CORS proxies and manages headers to avoid 
 * common "Preflight" (OPTIONS request) failures.
 */
async function fetchSecure(targetUrl: string): Promise<Response> {
  const auth = getAuthHeader();

  // Appending a timestamp prevents browser/proxy caching of error states
  const timestamp = Date.now();
  const cacheBusterUrl = `${targetUrl}${targetUrl.includes('?') ? '&' : '?'}_t=${timestamp}`;

  const proxyConfigs = [
    { 
      name: 'Codetabs', 
      url: (u: string) => `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(u)}` 
    },
    { 
      name: 'AllOrigins', 
      url: (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}` 
    },
    { 
      name: 'CorsProxyIO', 
      url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}` 
    }
  ];

  let lastError: string = "Connection pending";

  for (const proxy of proxyConfigs) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000); // 10s timeout for mobile stability

    try {
      const finalUrl = proxy.url(cacheBusterUrl);

      // We keep headers to the ABSOLUTE MINIMUM.
      // Adding extra headers (like Accept or Content-Type) triggers "Preflight" OPTIONS
      // requests which often fail on free proxies.
      const response = await fetch(finalUrl, {
        method: 'GET',
        headers: { 
          'Authorization': auth
        },
        signal: controller.signal,
        credentials: 'omit', // Prevents sending cookies which can trigger CORS blocks
        cache: 'no-store'
      });

      clearTimeout(timeoutId);

      if (response.ok) {
        return response;
      }

      if (response.status === 401 || response.status === 403) {
        throw new Error("API Authentication Failed");
      }

      lastError = `${proxy.name} (HTTP ${response.status})`;
    } catch (e: any) {
      clearTimeout(timeoutId);

      if (e.name === 'AbortError') {
        lastError = `${proxy.name} timed out`;
      } else {
        // This is where "Failed to fetch" usually originates
        lastError = `${proxy.name}: ${e.message || 'CORS/Network Error'}`;
      }

      console.warn(`Proxy fail: ${lastError}`);

      // If credentials failed, don't bother trying other proxies
      if (e.message?.includes("Authentication")) throw e;
    }
  }

  throw new Error(`Data Stream Offline: ${lastError}. Try switching from Wi-Fi to Mobile Data, or refreshing.`);
}

