    if (data.services && Array.isArray(data.services)) {
      data.services = data.services.filter(s => {
        if (!s.locationDetail.realtimeDepartureActual) return true;
        const depTime = s.locationDetail.realtimeDeparture || s.locationDetail.gbttBookedDeparture;
        if (!depTime) return true;
        const depMins = getSortTime(depTime, currentMinutes);
        return (currentMinutes - depMins) <= 15;
      });

      data.services.sort((a, b) => {
        const timeA = a.locationDetail?.gbttBookedDeparture || a.locationDetail?.realtimeDeparture || "0000";
        const timeB = b.locationDetail?.gbttBookedDeparture || b.locationDetail?.realtimeDeparture || "0000";
        return getSortTime(timeA, currentMinutes) - getSortTime(timeB, currentMinutes);
      });
    } else {
      data.services = [];
    }

    return data;
  } catch (error: any) {
    console.error('Departures fetch failed:', error);
    throw error;
  }
}

export async function fetchServiceDetails(serviceUid: string, runDate: string): Promise<ServiceDetail> {
  const formattedDate = runDate.replace(/-/g, '/');
  const targetUrl = `https://api.rtt.io/api/v1/json/service/${serviceUid}/${formattedDate}`;

  try {
    const response = await fetchSecure(targetUrl);
    return await response.json();
  } catch (error: any) {
    console.error('Service detail fetch failed:', error);
    throw error;
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Station, Service, ServiceDetail, LocationDetail } from './types';
import { fetchDepartures, fetchServiceDetails } from './services/rttService';
import { findStationCrs, getRouteCallingPoints, RouteStops } from './services/geminiService';
import { MAJOR_STATIONS, Icons } from './constants';

const RECENT_STATIONS_KEY = 'uk_rail_recent_stations_v4_stable';

const formatTime = (timeStr?: string) => {
  if (!timeStr || timeStr.length < 4) return "--:--";
  return `${timeStr.slice(0, 2)}:${timeStr.slice(2, 4)}`;
};

const calculateStatus = (location: LocationDetail) => {
  const planned = location.gbttBookedDeparture || location.gbttBookedArrival;
  const actual = location.realtimeDeparture || location.realtimeArrival;
  const isDeparted = location.realtimeDepartureActual === true;
  const isArrivedOnly = location.realtimeArrivalActual === true && !isDeparted;

  if (location.displayAs === 'CANCELLED_CALL') {
    return { 
      text: "STOP CANCELLED", 
      displayStatus: "CANCELLED", 
      color: "text-rose-500", 
      bg: "bg-rose-500/20", 
      isDeparted: false, 
      isArrivedOnly: false,
      isCancelled: true 
    };
  }

  if (!planned) return { text: "Scheduled", displayStatus: "Scheduled", color: "text-blue-400", bg: "bg-blue-400/10", isDeparted, isArrivedOnly, isCancelled: false };

  let diffText = "On Time";
  let statusColor = "text-emerald-400";
  let statusBg = "bg-emerald-400/10";

  if (actual && actual !== planned) {
    const pMin = parseInt(planned.slice(0, 2), 10) * 60 + parseInt(planned.slice(2, 4), 10);
    const aMin = parseInt(actual.slice(0, 2), 10) * 60 + parseInt(actual.slice(2, 4), 10);
    const estTime = formatTime(actual);
    let diff = aMin - pMin;
    if (diff < -1200) diff += 1440;
    if (diff > 1200) diff -= 1440;

    if (diff > 0) {
      diffText = `${diff}m Late (${estTime})`;
      statusColor = "text-rose-400";
      statusBg = "bg-rose-400/10";
    } else if (diff < 0) {
      diffText = `Early (${estTime})`;
      statusColor = "text-emerald-400";
      statusBg = "bg-emerald-400/10";
    }
  }

  return { 
    text: isDeparted ? "Departed" : isArrivedOnly ? "At Station" : diffText, 
    displayStatus: diffText, 
    color: statusColor, 
    bg: statusBg, 
    isDeparted, 
    isArrivedOnly,
    isCancelled: false
  };
};

const getFullDestinationName = (service: Service | ServiceDetail): string => {
  const dest = 'locationDetail' in service 
    ? (service.destination || service.locationDetail?.destination) 
    : (service.destination || null);

  if (Array.isArray(dest)) return dest[0]?.description || "Check Board";
  return (dest as any)?.description || "Check Board";
};

const App: React.FC = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Station[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);
  const [departures, setDepartures] = useState<Service[]>([]);
  const [selectedService, setSelectedService] = useState<ServiceDetail | null>(null);
  const [isServiceLoading, setIsServiceLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [enriching, setEnriching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isRefreshError, setIsRefreshError] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [recentStations, setRecentStations] = useState<Station[]>([]);

  const latestQueryRef = useRef('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(RECENT_STATIONS_KEY);
      if (saved) setRecentStations(JSON.parse(saved));
    } catch (e) {
      setRecentStations([]);
    }
  }, []);

  useEffect(() => {
    const handleFsChange = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(() => {});
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    latestQueryRef.current = searchQuery;
    if (searchQuery.trim().length < 2) {
      setSearchResults([]);
      setSearchError(null);
      return;
    }

    const timer = setTimeout(async () => {
      setIsSearching(true);
      setSearchError(null);
      try {
        const results = await findStationCrs(searchQuery);
        if (latestQueryRef.current === searchQuery) {
          setSearchResults(results || []);
          if (!results || results.length === 0) setSearchError("No stations found");
        }
      } catch (err: any) {
        if (latestQueryRef.current === searchQuery) setSearchError("Lookup Unavailable");
      } finally {
        if (latestQueryRef.current === searchQuery) setIsSearching(false);
      }
    }, 450);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const loadStationData = useCallback(async (station: Station, silent: boolean = false) => {
    if (!station?.crs) return;
    if (!silent) {
      setLoading(true);
      setError(null);
    }

    setSelectedStation(station);
    setSearchQuery('');

    try {
      const data = await fetchDepartures(station.crs);
      const services = data.services || [];

      setDepartures(prev => services.map(s => {
        const match = prev.find(p => p.serviceUid === s.serviceUid);
        return match ? { ...s, callingPoints: match.callingPoints } : s;
      }));

      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);

      if (!silent) {
        setRecentStations(prev => {
          const filtered = prev.filter(s => s.crs !== station.crs);
          const updated = [station, ...filtered].slice(0, 12);
          try { localStorage.setItem(RECENT_STATIONS_KEY, JSON.stringify(updated)); } catch (e) {}
          return updated;
        });
      }

      if (services.length > 0 && !silent) {
        setEnriching(true);
        const uniqueRoutes = services.slice(0, 8).map(s => ({
          origin: "Origin",
          destination: getFullDestinationName(s),
          via: data.location?.name || station.name
        })).filter((v, i, a) => a.findIndex(t => t.destination === v.destination) === i);

        getRouteCallingPoints(uniqueRoutes).then((enrichedResults: RouteStops[]) => {
          if (!enrichedResults) return;
          setDepartures(prev => prev.map(s => {
            const destName = getFullDestinationName(s).toLowerCase();
            const match = enrichedResults.find(r => 
              r.destination.toLowerCase().includes(destName) || destName.includes(r.destination.toLowerCase())
            );
            return match && match.stops.length > 0 ? { ...s, callingPoints: match.stops } : s;
          }));
        }).finally(() => setEnriching(false));
      }
    } catch (err: any) {
      setIsRefreshError(true);
      if (departures.length === 0 || !silent) {
        setError(err.message || "Network Timeout. Please check your signal.");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  }, [departures.length]);

  const handleServiceClick = useCallback(async (service: Service | { serviceUid: string, runDate: string }, silent: boolean = false) => {
    if (!silent) {
      setIsServiceLoading(true);
      setError(null);
    }
    try {
      const details = await fetchServiceDetails(service.serviceUid, service.runDate);
      setSelectedService(details);
      setLastUpdated(new Date());
      setError(null);
      setIsRefreshError(false);
    } catch (err: any) {
      setIsRefreshError(true);
      if (!selectedService || !silent) setError("Timeline unavailable. Try again in a moment.");
    } finally {
      if (!silent) setIsServiceLoading(false);
    }
  }, [selectedService]);

  const handleManualRefresh = () => {
    if (selectedService) handleServiceClick(selectedService, false);
    else if (selectedStation) loadStationData(selectedStation, false);
  };

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchResults.length > 0) {
      loadStationData(searchResults[0]);
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      if (selectedService) handleServiceClick(selectedService, true);
      else if (selectedStation) loadStationData(selectedStation, true);
    }, 45000); // 45s interval is safer for mobile proxies
    return () => clearInterval(interval);
  }, [selectedStation, selectedService, handleServiceClick, loadStationData]);

  if (!selectedStation) {
    const stations = recentStations.length > 0 ? recentStations : MAJOR_STATIONS;
    return (
      <div className="h-screen w-screen bg-[#0b1120] text-slate-200 flex flex-col items-center pt-16 md:pt-24 p-6 overflow-y-auto custom-scrollbar relative">
        <div className="absolute top-6 right-6">
          <button onClick={toggleFullscreen} className="p-2 bg-slate-900/60 border border-slate-800 hover:border-blue-500 rounded-xl text-slate-400 hover:text-white transition-all shadow-xl">
            {isFullscreen ? <Icons.FullscreenExit /> : <Icons.Fullscreen />}
          </button>
        </div>

        <div className="w-full max-w-xl animate-in">
          <header className="mb-10 text-center">
            <h1 className="text-4xl md:text-5xl font-black text-white italic uppercase tracking-tighter mb-2">UK Rail Live</h1>
            <p className="text-slate-500 text-[10px] uppercase tracking-[0.4em]">Real-time Departures</p>
          </header>

          <form onSubmit={handleSearchSubmit} className="bg-slate-900 border border-slate-800 rounded-2xl p-1 shadow-2xl mb-12">
            <div className="flex items-center px-4">
              <div className="text-slate-500 mr-3">
                {isSearching ? <div className="h-4 w-4 border-2 border-blue-500 border-t-transparent animate-spin rounded-full" /> : <Icons.Search />}
              </div>
              <input 
                type="text" 
                className="w-full py-4 bg-transparent focus:outline-none text-white font-bold text-lg"
                placeholder="Find station..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
              />
              {searchQuery.length > 0 && (
                <button type="submit" className="ml-2 p-2 text-blue-500 hover:text-blue-400 transition-colors">
                  <Icons.ChevronRight />
                </button>
              )}
            </div>
            {searchResults.length > 0 && (
              <div className="border-t border-slate-800 max-h-60 overflow-y-auto custom-scrollbar">
                {searchResults.map(s => (
                  <button type="button" key={s.crs} onClick={() => loadStationData(s)} className="w-full p-4 flex items-center justify-between hover:bg-white/5 transition-colors group text-left">
                    <span className="font-bold text-white group-hover:text-blue-400">{s.name}</span>
                    <span className="text-[10px] font-black bg-slate-800 px-2 py-1 rounded text-slate-400 uppercase tracking-widest">{s.crs}</span>
                  </button>
                ))}
              </div>
            )}
            {searchError && <div className="p-4 text-[10px] text-rose-500 font-black uppercase tracking-widest text-center border-t border-slate-800">{searchError}</div>}
          </form>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {stations.map(s => (
              <button key={s.crs} onClick={() => loadStationData(s)} className="p-3 bg-slate-900/40 border border-slate-800 hover:border-blue-500 rounded-xl text-[10px] font-bold text-slate-400 hover:text-white transition-all truncate text-center uppercase tracking-wider">
                {s.name}
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-screen bg-black text-slate-100 flex flex-col overflow-hidden">
      <nav className="h-16 bg-black/95 border-b border-white/5 px-4 md:px-8 flex items-center justify-between shrink-0 z-50">
        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1 mr-4 overflow-hidden">
          <div className="flex items-center gap-1 shrink-0">
            <button onClick={() => setSelectedStation(null)} className="p-2 text-slate-500 hover:text-white transition-colors" title="Home"><Icons.ChevronDoubleLeft /></button>
            {selectedService && <button onClick={() => setSelectedService(null)} className="p-2 text-slate-400 hover:text-white transition-colors"><Icons.ChevronLeft /></button>}
          </div>
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className="text-blue-500 font-black text-[10px] tracking-widest shrink-0">{selectedStation.crs}</span>
              <span className={`w-1.5 h-1.5 rounded-full animate-pulse shrink-0 ${isRefreshError ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]' : 'bg-emerald-500'}`} />
            </div>
            <h1 className="text-base md:text-lg font-black uppercase italic tracking-tighter leading-none w-full block truncate">
              {selectedService ? getFullDestinationName(selectedService) : selectedStation.name}
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          <div className="flex flex-col items-end mr-2 md:mr-4">
            <span className={`text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] mb-0.5 ${isRefreshError ? 'text-rose-500/40' : 'text-emerald-500/40'}`}>
              {isRefreshError ? 'SYNC FAILED' : 'LAST FEED'}
            </span>
            <span className={`mono text-xs md:text-base font-bold tracking-wider transition-colors ${isRefreshError ? 'text-rose-500' : 'text-emerald-400'}`}>
              {lastUpdated ? lastUpdated.toLocaleTimeString('en-GB') : "--:--"}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={handleManualRefresh} className={`p-2 bg-white/5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-all ${loading || isServiceLoading ? 'animate-spin text-blue-500' : ''}`}><Icons.Refresh /></button>
          </div>
        </div>
      </nav>

      <main className="flex-1 p-1 md:p-4 flex flex-col overflow-hidden max-w-[1800px] mx-auto w-full">
        <div className="flex-1 bg-[#0c0c0c] border border-white/5 rounded-2xl shadow-2xl flex flex-col overflow-hidden relative">
          {!selectedService ? (
            <div className="flex-1 flex flex-col overflow-hidden h-full">
              <div className="px-3 py-1.5 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <span className="text-[10px] font-bold text-blue-500 tracking-tight uppercase">Departure Board</span>
                <div className="text-[7px] font-bold text-zinc-600 uppercase tracking-widest">Live Feed v3.1.5</div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar divide-y divide-white/5">
                {loading && departures.length === 0 && !error ? (
                  <div className="h-full flex flex-col items-center justify-center gap-4">
                    <div className="h-10 w-10 border-[3px] border-blue-500/10 border-t-blue-500 animate-spin rounded-full" />
                    <span className="text-[8px] font-black uppercase tracking-[0.5em] text-slate-500">Establishing Stream...</span>
                  </div>
                ) : (departures.length === 0 && error) ? (
                  <div className="h-full flex flex-col items-center justify-center p-8 text-center">
                    <div className="text-2xl font-black italic uppercase text-zinc-800 mb-2 leading-none">Connection Idle</div>
                    <p className="text-[10px] text-zinc-500 mb-2 max-w-xs">{error}</p>
                    <p className="text-[8px] text-zinc-600 font-mono mb-6 uppercase tracking-widest">Diagnostics: Mobile Security Policy Intercept</p>
                    <button onClick={handleManualRefresh} className="px-6 py-3 bg-blue-600 text-white font-black uppercase tracking-widest text-[10px] rounded-lg hover:bg-blue-500 transition-colors shadow-lg">Force Reconnect</button>
                  </div>
                ) : (
                  departures.map((s, idx) => {
                    const status = calculateStatus(s.locationDetail);
                    const isGone = status.isDeparted;
                    const dest = getFullDestinationName(s);
                    return (
                      <button key={`${s.serviceUid}-${idx}`} onClick={() => handleServiceClick(s)} className={`w-full py-2.5 px-3 md:py-3 md:px-5 grid grid-cols-12 gap-2 md:gap-4 hover:bg-white/[0.02] active:bg-white/5 transition-colors text-left group ${isGone ? 'opacity-40' : ''}`}>
                        <div className="col-span-3 md:col-span-2 flex flex-col justify-center">
                          <span className={`text-xl md:text-3xl font-black mono tracking-tighter transition-colors leading-none ${isGone ? 'text-orange-500' : status.isArrivedOnly ? 'text-pink-500' : 'text-white group-hover:text-blue-400'}`}>
                            {formatTime(s.locationDetail.gbttBookedDeparture || s.locationDetail.realtimeDeparture)}
                          </span>
                          <span className={`text-[6.5px] md:text-[8px] font-black uppercase px-1 py-0.5 mt-1 rounded w-fit leading-tight ${status.bg} ${status.color}`}>
                            {status.text}
                          </span>
                        </div>
                        <div className="col-span-9 md:col-span-10 flex flex-col justify-center min-w-0">
                          <h3 className={`text-sm md:text-2xl font-black uppercase tracking-tighter leading-tight truncate ${isGone ? 'text-orange-500' : status.isArrivedOnly ? 'text-pink-500' : 'text-slate-100 group-hover:text-white'}`}>{dest}</h3>
                          <div className="flex items-center gap-1.5 mt-0.5 overflow-hidden whitespace-nowrap">
                            {s.callingPoints ? s.callingPoints.slice(0, 6).map((p, pIdx) => (
                              <React.Fragment key={pIdx}>
                                <span className={`text-[9px] md:text-[11px] font-medium transition-colors truncate ${isGone ? 'text-orange-600/70' : status.isArrivedOnly ? 'text-pink-600/70' : 'text-slate-500'}`}>{p}</span>
                                {pIdx < Math.min(s.callingPoints!.length, 6) - 1 && <span className="text-zinc-800 text-[6px]">•</span>}
                              </React.Fragment>
                            )) : <span className="text-[7px] font-black text-zinc-800 uppercase tracking-widest">{enriching ? 'EXTRACTING...' : 'DIRECT'}</span>}
                            {s.callingPoints && s.callingPoints.length > 6 && <span className="text-zinc-800 text-[9px]">+more</span>}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in h-full">
              <div className="px-3 py-1.5 bg-zinc-900/40 border-b border-white/5 flex items-center justify-between shrink-0">
                <span className="text-[10px] font-bold text-blue-500 tracking-tight uppercase">Journey Timeline</span>
                <div className="text-[7px] font-bold text-zinc-600 uppercase tracking-widest">{selectedService.atocName}</div>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar p-4">
                {(!selectedService.locations || error) ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <p className="text-[10px] text-zinc-500 mb-4">{error || "Timeline processing error."}</p>
                    <button onClick={handleManualRefresh} className="text-blue-500 font-bold uppercase text-[10px]">Retry Fetch</button>
                  </div>
                ) : (
                  <div className="max-w-2xl mx-auto space-y-5 relative pb-24">
                    <div className="absolute left-[29px] top-4 bottom-24 w-px bg-zinc-900/50" />
                    {selectedService.locations.map((loc, lIdx) => {
                      const status = calculateStatus(loc);
                      const isFinalStop = lIdx === selectedService.locations.length - 1;
                      const isDeparted = loc.realtimeDepartureActual === true || (isFinalStop && loc.realtimeArrivalActual === true);
                      const isArrivedOnly = loc.realtimeArrivalActual === true && !isDeparted && !isFinalStop;

                      let label = '';
                      if (status.isCancelled) label = "STOP CANCELLED";
                      else if (isDeparted) label = `DEPARTED - ${status.displayStatus.toUpperCase()}`;
                      else if (isArrivedOnly) label = `ARRIVED - ${status.displayStatus.toUpperCase()}`;
                      else label = status.displayStatus.toUpperCase();

                      return (
                        <div key={lIdx} className="flex gap-4 items-start relative z-10">
                          <div className="flex flex-col items-center w-14 shrink-0">
                            <span className={`mono text-[10px] font-bold ${status.isCancelled ? 'text-rose-900 line-through' : isDeparted ? 'text-orange-700' : isArrivedOnly ? 'text-pink-700' : 'text-slate-400'}`}>
                              {formatTime(loc.gbttBookedArrival || loc.gbttBookedDeparture)}
                            </span>
                            <div className={`w-2.5 h-2.5 rounded-full border-2 mt-1.5 transition-all ${
                              status.isCancelled 
                                ? 'bg-rose-950 border-rose-500' 
                                : isArrivedOnly 
                                  ? 'bg-pink-500 border-pink-500 scale-110 animate-pulse' 
                                  : isDeparted 
                                    ? 'bg-black border-orange-500' 
                                    : 'bg-black border-blue-500'}`} />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2">
                              <span className={`text-base font-black uppercase tracking-tight truncate ${status.isCancelled ? 'text-rose-900 line-through' : isDeparted ? 'text-orange-500' : isArrivedOnly ? 'text-pink-500' : 'text-white'}`}>{loc.description}</span>
                              <span className={`text-[7px] font-black px-1 py-0 rounded tracking-widest shrink-0 ${status.isCancelled ? 'bg-rose-500/10 text-rose-800' : isDeparted ? 'bg-orange-500/10 text-orange-800' : isArrivedOnly ? 'bg-pink-500/10 text-pink-800' : 'bg-white/5 text-zinc-700'}`}>{loc.crs}</span>
                            </div>
                            <div className={`text-[8px] uppercase font-bold mt-1 flex flex-wrap gap-2 ${status.isCancelled ? 'text-rose-800' : isDeparted ? 'text-orange-800' : isArrivedOnly ? 'text-pink-800' : 'text-zinc-500'}`}>
                              <span className={`px-1.5 py-0.5 rounded ${status.bg} ${status.color} font-black`}>{label}</span>
                              {loc.platform && !status.isCancelled && <span className="bg-zinc-900 px-1.5 py-0.5 rounded">PLAT {loc.platform}</span>}
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          )}
